sub I2F {
    my ($width, $value) = @_;
    !ref $width or &Error('I2F', @_);
    $value = &castI($value) or &Error('I2F', @_);
    if (defined &integer($width) && $value->[0] =~ /^(SX|ZX)$/) {
        my $subwidth = $value->[1];
