    # [SC] Test for unnecessarily guarded shift, and remove the guard.
    # Match:
    #   (I2F.n (SELECT
    #           (GT (P1) (CONST n-1))
    #           (SHR (Q1) (CONST n-1))
    #           (SHR (Q2) (P2))))
    #   where P1 == P2
    #   and   Q1 == Q2 == (SX.n (exp))
    # and replace with:
    #    (I2F.n (SHR (Q2) (P2)))
    if (   defined &integer($width)
        && $value->[0] eq 'SELECT'
        && $value->[1]->[0] eq 'GT'
        && $value->[2]->[0] eq 'SHR'
        && $value->[3]->[0] eq 'SHR') {
        my $p1 = $value->[1]->[1];
        my $k1 = &constant($value->[1]->[2]);
        my $q1 = $value->[2]->[1];
        my $k2 = &constant($value->[2]->[2]);
        my $q2 = $value->[3]->[1];
        my $p2 = $value->[3]->[2];
        if (   defined $k1 && $k1 == $width - 1
            && defined $k2 && $k2 == $k1
            && &Same($p1, $p2)
            && &Same($q1, $q2)
            && $q1->[0] eq 'SX'
            && $q1->[1] == $width) {
            $value = $value->[3];
        }
    }
    # [SC] Test for unnecessarily guarded shift, and remove the guard.
    # Match:
    #   (I2F.n (SELECT
    #           (GT (P1) (CONST n-1))
    #           (CONST 0)
    #           (SHL (Q1) (P2))))
    #   where P1 == P2
    # and replace with:
    #    (I2F.n (SHL (Q1) (P2)))
    if (   defined &integer($width)
        && $value->[0] eq 'SELECT'
        && $value->[1]->[0] eq 'GT'
        && $value->[3]->[0] eq 'SHL') {
        my $p1 = $value->[1]->[1];
        my $k1 = &constant($value->[1]->[2]);
        my $k2 = &constant($value->[2]);
        my $q1 = $value->[3]->[1];
        my $p2 = $value->[3]->[2];
        if (   defined $k1 && $k1 == $width - 1
            && defined $k2 && $k2 == 0
            && &Same($p1, $p2)) {
            $value = $value->[3];
        }
    }
    my $attributes = { TYPE=>'BitField', WIDTH=>$width, CODE=>\&I2F };
    return [ 'I2F', $width, $value, $attributes ];
