            my ($op, $code);
            ($op, $code) = ('SX', \&SX) if $value->[0] eq 'ZX';
            $value->[0] = $op;
            $value->[1] = $width;
            $value->[3]{CODE} = $code;
            $value->[3]{WIDTH} = $width;
            return $value;
        }
