# The bit width a LOAD/STORE sees at a Location.  An AGGL/AGGB aggregate is
# `extent` cells of the storage's cell width (extent 0 when not a constant, as
# before).  A SLICE is its own static width (array-child 1) -- it does not read a
# storage width, because its child Location already carries one.
sub locationWidth {
    my ($location) = @_;
    return $$location[1] if $$location[0] eq 'SLICE';
    my $extent = $$location[3];
    my $cells = ($$extent[0] eq 'CONST')? $$extent[1]: 0;
    return $cells * $Storage{$$location[1]}->{WIDTH};
}

sub LOAD {
    my ($stage, $location) = @_;
    $stage = "_" unless defined $stage;
    my $attributes = {};
    unless ($partial_initialization) {
        $attributes = { TYPE=>'BitField', WIDTH=>&locationWidth($location) };
    }
    return [ 'LOAD', $stage, $location, $attributes ];
}

sub STORE {
    my ($stage, $location, $field, $mask) = @_;
    $stage = "_" unless defined $stage;
    unless ($partial_initialization) {
        if ($field->[-1]->{TYPE} ne 'BitField') {
            $field = &I2F(&locationWidth($location), &castI($field));
        }
    }
    return [ 'STORE', $stage, $location, $field ] unless defined $mask;
    return [ 'STORE', $stage, $location, $field, $mask ];
}

sub PROBE {
    my ($stage, $location, $attributes) = @_;
    $attributes = { } unless defined $attributes;
    $stage = "_" unless defined $stage;
    my $name = $$location[1];
    $$attributes{TYPE} = 'Boolean';
    return [ 'PROBE', $stage, $location, $attributes ];
}

sub AGGL {
    my ($storage, $address, $extent, $proxy) = @_;
    &Error("PROBE unknown storage", @_) if ref $Storage{$storage} ne 'HASH';
    my $width = $Storage{$storage}->{WIDTH};
    &Error("$storage width undefined", @_) unless defined $width;
    # The optional $proxy attributes this storage access to an instruction
    # operand -- a run-time-indexed register-file read/write whose Storage
    # address cannot be a decode-time operand (e.g. XACCESSO/XALIGNO reading a
    # register selected by a run-time value within the block operand names).
    # It rides in slot 4, invisible to CodeGen/Width (which read [1..3]); the
    # dependency back-ends recover the block's registers from it.
    return [ 'AGGL', $storage, $address, $extent ] unless defined $proxy;
    return [ 'AGGL', $storage, $address, $extent, $proxy ];
}

sub AGGB {
    my ($storage, $address, $extent, $proxy) = @_;
    &Error("PROBE unknown storage", @_) if ref $Storage{$storage} ne 'HASH';
    my $width = $Storage{$storage}->{WIDTH};
    &Error("$storage width undefined", @_) unless defined $width;
    return [ 'AGGB', $storage, $address, $extent ] unless defined $proxy;
    return [ 'AGGB', $storage, $address, $extent, $proxy ];
}

# A sub-cell slice of a Location: the SLICE_LOC of lambda-RTL (Ramsey & Davidson
# 1999, the ADL this Location model descends from -- see DOC/Behavior.md #8).  It
# carves a $width-bit field at bit $offset out of the whole-cell $location, and is
# an assignable location in its own right.  $width is a static constant (the
# field's type is known); $offset is an Integer, constant for [k]/[k1..k2] or an
# expression for [k bits at e] (the run-time-indexed lane select).  A lowering
# pass rewrites SLICE to whole-cell LOAD/STORE plus ring operations before CodeGen
# and Width ever see it, so nothing downstream is taught the node -- read becomes a
# value slice, write a bitInsert read-modify-write.
sub SLICE {
    my ($width, $location, $offset) = @_;
    &Error("SLICE width must be a positive constant", @_)
        unless defined $width && $width =~ /^\d+$/ && $width > 0;
    &Error("SLICE of a non-location", @_) unless ref $location eq 'ARRAY';
    &Error("SLICE offset is not an Integer", @_) unless ref $offset eq 'ARRAY';
    return [ 'SLICE', $width, $location, $offset ];
}

# Lower every SLICE location to whole-cell LOAD/STORE plus ring operations, so
# nothing downstream (Width, CodeGen) is ever taught the node.  This is lambda-
# RTL's slice rewrite (Ramsey & Davidson 1999; DOC/Behavior.md #8):
#
#   read   LOAD.s (SLICE.w l off)          -> I2F.w (SHR (F2I.W (LOAD.s l)) off)
#   write  STORE.s (SLICE.w l off) field   -> STORE.s l
#            (I2F.W (IOR (AND (F2I.W (LOAD.s l)) (NOT (SHL m off)))   ; cell, window cleared
#                        (SHL (ZX.w (F2I.w field)) off)))            ; new field placed
#
# with W the underlying aggregate's width and m = 2^w-1 (built as ZX.w of -1, so
# no big literal is minted for a 256-bit XVR lane).  castI turns the LOAD BitField
# into the unsigned W-bit integer ZX.W(F2I.W(.)), which is what makes the read SHR
# logical.  A dynamic offset (the [k bits at e] lane select) rides through
# unchanged; its result types at W under the enclosing I2F.W, which is sound.
# Runs after Expand (so an operand's register file, substituted in as a SLICE by
# Access.pl, is lowered too) and before the width check.  Bottom-up, so a slice in
# an offset or a stored value is lowered first; a slice of a slice is refused
# rather than mis-lowered (it is not needed, and silence would be worse).
sub Deslice {
    my ($this) = @_;
    return $this unless ref $this eq 'ARRAY';
    for my $i (0 .. $#$this) {
        $this->[$i] = &Deslice($this->[$i]) if ref $this->[$i] eq 'ARRAY';
    }
    my $location = $this->[2];
    return $this unless ref $location eq 'ARRAY' && $location->[0] eq 'SLICE';
    my ($tag, $stage) = @{$this}[0, 1];
    my ($w, $l, $off) = @{$location}[1, 2, 3];
    &Error("Deslice: a slice of a slice is not supported", $this)
        if ref $l eq 'ARRAY' && $l->[0] eq 'SLICE';
    if ($tag eq 'LOAD') {
        return &I2F($w, &SHR(&castI(&LOAD($stage, $l)), $off));
    }
    if ($tag eq 'STORE') {
        &Error("Deslice: a masked STORE to a slice", $this) if defined $this->[4];
        my $field   = $this->[3];
        my $W       = &locationWidth($l);
        my $mask    = &ZX($w, &CONST(-1));                        # 2^w - 1
        my $cleared = &AND(&castI(&LOAD($stage, $l)), &NOT(&SHL($mask, $off)));
        my $placed  = &SHL(&ZX($w, &F2I($w, $field)), $off);
        return &STORE($stage, $l, &I2F($W, &IOR($cleared, $placed)));
    }
    return $this;
}

sub MACRO {
    my (@arguments) = @_;
    return [ 'MACRO', @arguments ];
}

sub FOR {
    my (@arguments) = @_;
    my $ident = $arguments[0];
    my $range = $arguments[1];
    my $contents = &SEQ($arguments[2]);
    return [ 'FOR', $ident, $range, @{$contents} ];
}

sub RANGE {
    my (@arguments) = @_;
    my ($begin, $end, $step) = @arguments;
    if ($step == 0) {
        die "Malformed range: step is zero.";
    } elsif (($end - $begin) / $step < 0) {
        die "Malformed range: $end will never be reached.";
    } elsif (($end - $begin) % $step != 0) {
        die "Malformed range: $end - $begin not a multiple of $step."
    }
    return [ 'RANGE', @arguments ];
}

sub SECTION {
    my (@arguments) = @_;
    if (scalar @arguments == 2) {
        return [ 'SECTION', $arguments[0], $arguments[1] ];
    } else {
        return [ 'SECTION', $arguments[1], 0 ];
    }
}

sub SKIP {
    my (@arguments) = @_;
    return [ 'SKIP', @arguments ];
}

sub CANCEL {
    return [ 'CANCEL' ];
}

sub SEQ {
    my @contents; map {
        if (ref $_ eq 'ARRAY' && $_->[0] eq 'SEQ') {
            push @contents, @{$_}[1 .. @{$_}-1];
        } else {
            push @contents, $_;
        }
      } grep {
        ref $_ ne 'ARRAY' || $_->[0] ne 'SKIP'
      } @_;
    if (@contents == 0) {
        return &SKIP();
    } elsif (@contents == 1) {
        return $contents[0];
    }
    return [ 'SEQ', @contents ];
}

sub IF {
    my ($test, $then, $else) = @_;
    $test = &castB($test) or &Error('IF', @_);
    if ($then->[0] eq 'SKIP' && $else->[0] eq 'SKIP') {
        return &SKIP();
    } elsif ($test->[0] eq 'FALSE') {
        return $else;
    } elsif ($test->[0] eq 'TRUE') {
        return $then;
    } elsif (&Same($then, $else)) {
        return $then;
    }
    if ($then->[0] eq 'SEQ' && $else->[0] eq 'SEQ') {
        # Try to extract a common suffix from the $then and $else sequences.
        my @then = @{$then}[1 .. @{$then}-1];
        my @else = @{$else}[1 .. @{$else}-1];
        my @same;
        while (@then > 1 && @else > 1 && &Same($then[-1], $else[-1])) {
            my $same = pop @then; pop @else;
            unshift @same, $same;
        }
        if (@same) {
            my $if = [ 'IF', $test, &SEQ(@then), &SEQ(@else) ];
            return &SEQ($if, @same);
        }
    }
    return [ 'IF', $test, $then, $else ];
}

#
#  Compute a rank for a tree.
#    The ranking is used to rearrange operand order
#    for commutative operators: higher ranked trees are
#    moved to lhs.
#
sub treeRank {
    my ($tree) = @_;
    if ($tree->[0] eq 'METHOD') {
        # Method trees always rank >= 32768.
        # Higher ranks for lower proxies.
        my $proxy = substr $tree->[1], 1, 1;
        return ((128 - $proxy) << 16);
    } else {
        my $result = 1;
        if ($tree->[0] eq 'CONST' &&
            $tree->[-1]->{TYPE} eq 'Integer') {
            $result = abs(&constant($tree));
            $result = 32767 if $result > 32767;
        } else {
            if ($tree->[0] =~ /^(SX|ZX)$/) {
                $result = $tree->[1];
            }
            foreach my $child (grep { ref $_ eq 'ARRAY' } @{$tree}) {
                $result += &treeRank($child);
            }
        }
        return $result;
    }
}

#
# Build a list of operands of a given operator.
#
sub operandsOf {
    my @result;
    my ($code, $tree) = @_;
    if (defined $tree->[-1]->{CODE} && $tree->[-1]->{CODE} == $code) {
        @result = ( &operandsOf($code, $tree->[1]), &operandsOf($code, $tree->[2]) );
    } else {
        @result = ( $tree );
    }
    return @result;
}

#
# Commute the given syntax tree so that low METHOD proxy numbers appear first.
#
sub Commute {
    my ($tree) = @_;
    # Recursive Commute.
    my @arguments = map {
        $_ = ref $_ eq 'ARRAY'? &Commute($_): $_;
      } @{$tree}[1 .. @{$tree}-1];
    if ($tree->[0] =~ /^(ADD|MUL|AND|IOR|XOR|MIN|MAX|ANDL|IORL|XORL)$/) {
        my $code = $tree->[-1]->{CODE};
        my @opds = sort { &treeRank($b) <=> &treeRank($a); } &operandsOf($code, $tree);
        foreach my $opd (@opds) {
            #print STDERR "Rank ", &Pretty($opd, " "),"  = ";
            #printf STDERR "%x\n", &treeRank($opd);
        }
        $tree = shift @opds;
        foreach my $opd (@opds) {
            $tree = &$code($tree, $opd);
        }
    } elsif ($tree->[0] =~ /^(NE|EQ|GT|LE|GE|LT)$/) {
        my ($tree_1, $tree_2) = ($tree->[1], $tree->[2]);
        my ($rank_1, $rank_2) = (&treeRank($tree_1), &treeRank($tree_2));
        if ($rank_1 lt $rank_2) {
            $tree->[1] = $tree_2;
            $tree->[2] = $tree_1;
            if    ($tree->[0] eq 'GT') { $tree->[0] = 'LT' }
            elsif ($tree->[0] eq 'LE') { $tree->[0] = 'GE' }
            elsif ($tree->[0] eq 'GE') { $tree->[0] = 'LE' }
            elsif ($tree->[0] eq 'LT') { $tree->[0] = 'GT' }
            #print STDERR "Commuted $tree->[0]!\n";
        }
    } elsif ($tree->[0] eq 'SELECT') {
        my ($tree_1, $tree_2, $tree_3) = ($tree->[1], $tree->[2], $tree->[3]);
        if ($tree_1->[0] =~ /^(NE|EQ|GT|LE|GE|LT)$/) {
            my ($rank_2, $rank_3) = (&treeRank($tree_2), &treeRank($tree_3));
            if ($rank_2 lt $rank_3) {
                $tree->[2] = $tree_3;
                $tree->[3] = $tree_2;
                if    ($tree_1->[0] eq 'GT') { $tree_1->[0] = 'LE' }
                elsif ($tree_1->[0] eq 'LE') { $tree_1->[0] = 'GT' }
                elsif ($tree_1->[0] eq 'GE') { $tree_1->[0] = 'LT' }
                elsif ($tree_1->[0] eq 'LT') { $tree_1->[0] = 'GE' }
                elsif ($tree_1->[0] eq 'EQ') { $tree_1->[0] = 'NE' }
                elsif ($tree_1->[0] eq 'NE') { $tree_1->[0] = 'EQ' }
                #print STDERR "Commuted $tree->[0]!\n";
            }
        }
    }
    return $tree;
}

#
# True if the two given syntax trees have the same contents.
#
sub Same {
    my ($this, $that) = @_;
    if (ref $this eq ref $that) {
        if (ref $this eq 'ARRAY') {
            my @this = grep { ref $_ ne 'HASH' } @{$this};
            my @that = grep { ref $_ ne 'HASH' } @{$that};
            while (@this && @that) {
                my $this = shift @this;
                my $that = shift @that;
                return 0 unless &Same($this, $that);
            }
            return (@this == @that);
        } elsif (!ref $this) {
            return ($this eq $that);
        }
        return 1;
    }
    return 0;
}

#
# Reorder the given syntax tree according to the stages.
#
sub Reorder {
    my ($tree) = @_;
    if (ref $tree eq 'ARRAY') {
        # Save attributes if any.
        my $attributes = undef;
        if (ref $tree->[-1] eq 'HASH') {
            $attributes = pop @{$tree};
        }
        # Special processing of SEQ.
        if ($tree->[0] eq 'SEQ') {
            # Sinks the COMMIT(s).
            my %proxy;
            my @commits = grep {
                !$proxy{$_->[2]}++;
              } sort {
                $a->[1] <=> $b->[1]
              } grep {
                ref $_ eq 'ARRAY' && $_->[0] eq 'COMMIT'
              } @{$tree};
            my @newtree = map {
                $_ = &Reorder($_)
              } grep {
                ref $_ ne 'ARRAY' || $_->[0] ne 'COMMIT'
              } @{$tree};
            $tree = [ @newtree, @commits ];
        }
        # Restore attributes if any.
        if (defined $attributes) {
            push @{$tree}, $attributes;
        }
    }
    return $tree;
}

#
# Normalize the given syntax tree using PruneWrite.
#
sub Normalize {
    my ($tree) = @_;
    ($tree) = &PruneWrite($tree);
    return $tree;
}

#
# Prune WRITE statements that are not used.
#
sub PruneWrite {
    my ($tree, $uses) = @_;
    &Error('PruneWrite', $tree, $uses) unless ref $tree eq 'ARRAY';
    if (ref $uses) { $uses = { %$uses } }
    else { $uses = { } }
    # Save attributes if any.
    my $attributes = undef;
    if (ref $tree->[-1] eq 'HASH') {
        $attributes = pop @{$tree};
    }
    # Process tree.
    if ($tree->[0] eq 'IF') {
        # IF: union the uses of children.
        my ($test, $uses1) = &PruneWrite($tree->[1], $uses);
        my ($then, $uses2) = &PruneWrite($tree->[2], $uses);
        my ($else, $uses3) = &PruneWrite($tree->[3], $uses);
        $tree->[1] = $test;
        $tree->[2] = $then;
        $tree->[3] = $else;
        $uses = { %$uses1, %$uses2, %$uses3 };
    } elsif ($tree->[0] eq 'WRITE' && !length($tree->[1])) {
        # WRITE: remove name from uses, change to SKIP if no uses.
        my $name = $tree->[2];
        my $value = $tree->[3];
        if (defined $$uses{$name}) {
            $$uses{$name} = undef;
            ($value, $uses) = &PruneWrite($value, $uses);
            $tree->[3] = $value;
        } else {
            $tree = &SKIP();
        }
    } elsif ($tree->[0] eq 'READ') {
        # READ: add name to uses.
        my $name = $tree->[2];
        ++$$uses{$name};
    } else {
        # PruneWrite non-IF children in reverse order.
        my @newtree = reverse map {
            my $child = $_;
            if (ref $child eq 'ARRAY') {
                ($child, $uses) = &PruneWrite($child, $uses);
            }
            $child;
          } reverse @{$tree};
        $tree = [ @newtree ];
    }
    # Restore attributes if any.
    if (defined $attributes) {
        push @{$tree}, $attributes;
    }
    return ($tree, $uses);
}

#
# Simplify the given syntax tree.
#
sub Simplify {
    my ($tree) = @_;
    # Simplify children.
    my @arguments = map {
        $_ = ref $_ eq 'ARRAY'? &Simplify($_): $_;
      } @{$tree}[1 .. @{$tree}-1];
    my $attributes = $tree->[-1];
    # Reinterpret the operators for constant folding etc.
    if (ref $attributes eq 'HASH') {
        my $code = $attributes->{CODE};
        $tree = &$code(@arguments) if defined $code;
    }
    if ($tree->[0] eq 'SEQ') {
        # Processing a SEQ.
        # Try to merge IF statements with common test.
        my $prev_if;
        map {
            if (ref $_ eq 'ARRAY') {
                if ($_->[0] eq 'IF') {
                    if (defined $prev_if && &Same($prev_if->[1], $_->[1])) {
                        $_->[2] = &Simplify(&SEQ($prev_if->[2], $_->[2]));
                        $_->[3] = &Simplify(&SEQ($prev_if->[3], $_->[3]));
                        $prev_if->[0] = 'SKIP';
                    }
                    $prev_if = $_;
                } elsif ($_->[0] ne 'SKIP') {
                    $prev_if = undef;
                }
            } else {
                $prev_if = undef;
            }
          } @{$tree};
        $tree = &SEQ(@{$tree}[1 .. @{$tree}-1]);
    } elsif ($tree->[0] eq 'IF') {
        # Processing a IF.
        my ($test, $then, $else) = ($tree->[1], $tree->[2], $tree->[3]);
        if ($then->[0] eq 'STORE' && $else->[0] eq 'STORE' &&
            !defined($then->[4]) && !defined($else->[4]) &&
            $then->[1] eq $else->[1] && &Same($then->[2], $else->[2]) &&
            $then->[3]->[0] eq 'I2F' && $else->[3]->[0] eq 'I2F' &&
            &Same($then->[3]->[1], $else->[3]->[1])) {
         # Convert IF into SELECT.  Note that SELECT works on Integers: move I2F
         # outside SELECT to keep with STORE.
            my $select = &SELECT(&Clone($test), $then->[3]->[2], $else->[3]->[2]);
            my $field = &I2F($then->[3]->[1], $select);
            $tree = &STORE($then->[1], $then->[2], $field);
        } else {
            # Try to convert prefix and/or suffix of sequence into SELECTs.
            my @then = $then->[0] eq 'SEQ' ? @{$then}[1 .. @{$then}-1] : ($then);
            my @else = $else->[0] eq 'SEQ' ? @{$else}[1 .. @{$else}-1] : ($else);
            my (@prefix, @suffix);
            while (@then && @else) {
                my ($thenI, $elseI) = ($then[0], $else[0]);
                if ($thenI->[0] eq 'WRITE' && $elseI->[0] eq 'WRITE' &&
                    $thenI->[1] eq $elseI->[1] && $thenI->[2] eq $elseI->[2]) {
                    my $select = &SELECT(&Clone($test), $thenI->[3], $elseI->[3]);
                    push @prefix, &WRITE($thenI->[1], $thenI->[2], $select);
                    shift @then; shift @else; next;
                }
                last;
            }
            while (@then && @else) {
                my ($thenI, $elseI) = ($then[-1], $else[-1]);
                if ($thenI->[0] eq 'WRITE' && $elseI->[0] eq 'WRITE' &&
                    $thenI->[1] eq $elseI->[1] && $thenI->[2] eq $elseI->[2]) {
                    my $select = &SELECT(&Clone($test), $thenI->[3], $elseI->[3]);
                    unshift @suffix, &WRITE($thenI->[1], $thenI->[2], $select);
                    pop @then; pop @else; next;
                }
                last;
            }
            my $if = &IF($test, &SEQ(@then), &SEQ(@else));
            $tree = &SEQ(@prefix, $if, @suffix);
        }
    }
    return $tree;
}

#
# Check a syntax tree for structural invariants.
#
my %Expression = (
    UNDEF=>'Integer',
    METHOD=>'Integer',
    CONST=>'Integer',
    READ=>'Integer',
    ACCESS=>'Integer',
    PROPERTY=>'Integer',
    APPLY=>'Integer',
    F2I=>'Integer',
    SX=>'Integer',
    ZX=>'Integer',
    SAT=>'Integer',
    SATU=>'Integer',
    CLZ=>'Integer',
    CLS=>'Integer',
    CTZ=>'Integer',
    CBS=>'Integer',
    SWAP=>'Integer',
    ROR=>'Integer',
    ROL=>'Integer',
    SELECT=>'Integer',
    ADD=>'Integer',
    SUB=>'Integer',
    MUL=>'Integer',
    DIV=>'Integer',
    REM=>'Integer',
    MOD=>'Integer',
    SHR=>'Integer',
    SHL=>'Integer',
    AND=>'Integer',
    IOR=>'Integer',
    XOR=>'Integer',
    MIN=>'Integer',
    MAX=>'Integer',
    NOT=>'Integer',
    NEG=>'Integer',
    ABS=>'Integer',
    B2I=>'Integer',
    TRUE=>'Boolean',
    FALSE=>'Boolean',
    TEST=>'Boolean',
    NE=>'Boolean',
    EQ=>'Boolean',
    GT=>'Boolean',
    LE=>'Boolean',
    GE=>'Boolean',
    LT=>'Boolean',
    ANDL=>'Boolean',
    IORL=>'Boolean',
    XORL=>'Boolean',
    PROBE=>'Boolean',
    NOTL=>'Boolean',
    I2B=>'Boolean',
  );
sub Check {
    my ($this) = @_;
    if (ref $this eq 'ARRAY') {
        my $operator = $this->[0];
        # Check each Expression has an Abstract.
        if ($Expression{$operator}) {
            my $abstract = $this->[-1];
            unless (ref $abstract eq 'HASH') {
                confess "Missing Abstract:\n", Dumper($this);
            }
        }
        map { &Check($_) } @{$this};
    }
}

#
# Clone a syntax tree with optional node replacement.
#
sub Clone {
    my ($this, $node, $replace) = @_;
    if (ref $this eq 'ARRAY') {
        if (defined $node && $node eq $this->[0]) {
            return $replace;
        }
        my @that; map {
            push @that, &Clone($_, $node, $replace);
          } @{$this};
        return \@that;
    } elsif (ref $this eq 'HASH') {
        my %that = %{$this};
        return \%that;
    } elsif (!ref $this) {
        return $this;
    }
    return undef;
}

#
# Rename the sequential WRITEs to a variable or proxy into single assigments.
#
my %renamePhi;
my %renameRefs;
sub Rename {
    my ($tree) = @_;
    %renamePhi = ();
    %renameRefs = ();
    my $counter = 0;
    &rename($tree, { }, \$counter);
    return $tree;
}

sub rename {
    my ($this, $reachingVals, $counter) = @_;
    return { } if ref $this ne 'ARRAY';
    my %localDefs = ();
    if ($this->[0] eq 'READ') {
        my $name = $this->[2];
        my $temp = $reachingVals->{$name};
        &renameUse($this, $temp) if defined $temp;
    } elsif ($this->[0] eq 'WRITE' && !length($this->[1])) {
        my $name = $this->[2];
        my $rhsDefs = &rename($this->[3], $reachingVals, $counter);
        die "Unexpected rhs expression" if scalar keys %{$rhsDefs};
        my $oldTemp = $localDefs{$name};
        &renameKill($oldTemp) if defined $oldTemp;
        my $newTemp = sprintf("__r%03d", ++$$counter);
        $reachingVals->{$name} = $newTemp;
        push @{$renameRefs{$newTemp}}, $this;
        $localDefs{$name} = $newTemp;
    } elsif ($this->[0] eq 'SEQ') {
        map {
            my $seqDefs = &rename($_, $reachingVals, $counter);
            while (my ($name, $seqTemp) = each %{$seqDefs}) {
                my $oldTemp = $localDefs{$name} unless defined $renamePhi{$seqTemp};
                &renameKill($oldTemp) if defined $oldTemp;
                $localDefs{$name} = $seqTemp;
            }
          } @{$this};
    } elsif ($this->[0] eq 'IF') {
        my %reachingValsTHEN = %{$reachingVals};
        my %reachingValsELSE = %{$reachingVals};
        my $ifDefs = &rename($this->[1], $reachingVals, $counter);
        my $thenDefs = &rename($this->[2], \%reachingValsTHEN, $counter);
        my $elseDefs = &rename($this->[3], \%reachingValsELSE, $counter);
        die "Unexpected if expression" if scalar keys %{$ifDefs};
        foreach my $name (sort keys %{$thenDefs}) {
            my $thenTemp = $thenDefs->{$name};
            my $elseTemp = $elseDefs->{$name};
            if (defined $elseTemp && !defined $renamePhi{$elseTemp}) {
                my $oldTemp = $localDefs{$name} unless defined $renamePhi{$thenTemp};
                &renameKill($oldTemp) if defined $oldTemp;
            }
            my $newTemp = sprintf("__r%03d", ++$$counter);
            if (defined $elseTemp) {
                $renamePhi{$newTemp} = [ $thenTemp, $elseTemp ];
                delete $elseDefs->{$name};
            } else {
                my $oldTemp = $reachingVals->{$name};
                push @{$renamePhi{$newTemp}}, $oldTemp if defined $oldTemp;
                push @{$renamePhi{$newTemp}}, $thenTemp;
            }
            $reachingVals->{$name} = $newTemp;
            $localDefs{$name} = $newTemp;
        }
        foreach my $name (sort keys %{$elseDefs}) {
            my $elseTemp = $elseDefs->{$name};
            die "Unexpected behavior" if defined $thenDefs->{$name};
            my $oldTemp = $reachingVals->{$name};
            my $newTemp = sprintf("__r%03d", ++$$counter);
            push @{$renamePhi{$newTemp}}, $oldTemp if defined $oldTemp;
            push @{$renamePhi{$newTemp}}, $elseTemp;
            $reachingVals->{$name} = $newTemp;
            $localDefs{$name} = $newTemp;
        }
    } else {
        map {
            my $exprDefs = &rename($_, $reachingVals, $counter);
            die "Unexpected expression" if scalar keys %{$exprDefs};
          } @{$this};
    }
    return \%localDefs;
}

sub renameUse {
    my ($this, $temp) = @_;
    &renamePhiUse($temp) if defined $renamePhi{$temp};
    push @{$renameRefs{$temp}}, $this;
}

sub renamePhiUse {
    my ($temp) = @_;
    map {
        &renamePhiUse($_) if defined $renamePhi{$_};
        push @{$renameRefs{$temp}}, @{$renameRefs{$_}} if defined $renameRefs{$_};
        delete $renameRefs{$_};
      } @{$renamePhi{$temp}};
    delete $renamePhi{$temp};
}

sub renameKill {
    my ($temp) = @_;
    if (defined $renamePhi{$temp}) {
        map {
            &renameKill($_);
            delete $renameRefs{$_};
          } @{$renamePhi{$temp}};
        delete $renamePhi{$temp};
    } else {
        map { $_->[1] = $temp; } @{$renameRefs{$temp}};
        delete $renameRefs{$temp};
    }
}

#
# Expand the ACCESS and COMMIT nodes.
#
sub Expand {
    my ($this, $accessTable, $commitTable, $node, $replace) = @_;
    croak "Expand needs a Behavior parse tree" if ref $this ne 'ARRAY';
    croak "Expand needs an access table" if ref $accessTable ne 'HASH';
    croak "Expand needs a commit table" if ref $commitTable ne 'HASH';
    croak "Expand needs a replace table" if defined $node && ref $replace ne 'HASH';
    my $actions = { };
    if ($this->[0] ne 'SEQ') {
        my $wrap = [ $this ];
        &expand($wrap, $accessTable, $commitTable, $node, $replace, $actions);
        $this = $wrap->[0];
    } else {
        &expand($this, $accessTable, $commitTable, $node, $replace, $actions);
    }
    return (&Simplify($this), $actions);
}

sub expand {
    my ($this, $accessTable, $commitTable, $node, $replace, $actions) = @_;
    return if ref $this ne 'ARRAY';
    my $index = 0;
    foreach my $child (@{$this}) {
        if (ref $child eq 'ARRAY') {
            if ($child->[0] eq 'ACCESS') {
                my $stage = $child->[1];
                my $proxy = $child->[2];
                my $expand = $accessTable->{$proxy};
                if (defined $expand) {
                    if (defined $node && defined $replace->{$proxy}) {
                        $expand = &Clone($expand, $node, $replace->{$proxy});
                    } else {
                        $expand = &Clone($expand);
                    }
                    if (   $expand->[0] =~ /^(F2I)$/
                        && $expand->[2]->[0] eq 'LOAD') {
                        $expand->[2]->[1] = $stage;
                    }
                    $this->[$index] = $expand;
                    $actions->{$proxy}->{ACCESS} = $stage;
                } else { die "Missing ACCESS expand for $proxy" }
            } elsif ($child->[0] eq 'COMMIT') {
                my $stage = $child->[1];
                my $proxy = $child->[2];
                my $value = $child->[3];
                my $mask = $child->[4];
                my $expand = $commitTable->{$proxy};
                if (defined $expand) {
                    if (defined $node && defined $replace->{$proxy}) {
                        $expand = &Clone($expand, $node, $replace->{$proxy});
                    } else {
                        $expand = &Clone($expand);
                    }
                    if ($expand->[0] eq 'STORE') {
                        $expand->[1] = $stage;
                        my $field = $expand->[3];
                        if ($field->[0] eq 'I2F') {
                            my $width = $field->[1];
                            $expand->[3] = &I2F($width, $value);
                        } else {
                            &Error("Expecting I2F in COMMIT expansion", $expand);
                        }
                        $expand->[4] = $mask if defined $mask;
                        $actions->{$proxy}->{COMMIT} = $stage;
                    } elsif ($expand->[0] =~ /^SKIP/) {
                    } else {
                        &Error("Unxepected $expand->[0] in COMMIT expansion", $expand);
                    }
                    $this->[$index] = $expand;
                } else { die "Missing COMMIT expand for $proxy" }
            } elsif ($child->[0] eq 'METHOD') {
                my $proxy = $child->[1];
                $actions->{$proxy}->{METHOD} = -1;
            }
        }
        $index++;
    }
    map {
        &expand($_, $accessTable, $commitTable, $node, $replace, $actions);
      } @{$this};
}

#
# Transform sequential Behavior into parallel Behavior:
#   - Forward substitute the WRITE into the READ
#   - Remove dead WRITEs
#
my %parallel_reads;
my $if_count;

sub Parallel {
    my ($tree, $opcodeID) = @_;
    %parallel_reads = ();
    $if_count = 0;
    &if_count($tree);
    if ($if_count < 8) {
        $tree = &parallel($tree, {});
        $tree = &remove_dead_writes($tree);
        $tree = &propagate_conditions($tree, [], []);
        return &Commute(&Simplify($tree));
    }
    print STDERR "IF count=$if_count,\tskip Parallel($opcodeID)\n";
    return $tree;
}

sub if_count {
    my ($this) = @_;
    return if ref $this ne 'ARRAY';
    if ($this->[0] eq 'IF') {
        $if_count++;
    }
    map { &if_count($_) } @$this;
}

sub parallel {
    my ($this, $reachingVals) = @_;
    return $this if ref $this ne 'ARRAY';
    if ($this->[0] eq 'READ') {
        my $Variable = $this->[2];
        my $value = $$reachingVals{$Variable};
        if (defined $value) {
            return &Clone($value);
        } else {
            $parallel_reads{$Variable}++;
        }
    } elsif ($this->[0] eq 'WRITE' && !length($this->[1])) {
        $this->[3] = &parallel($this->[3], $reachingVals);
        $$reachingVals{$this->[2]} = $this->[3];
    } elsif ($this->[0] eq 'IF') {
        $this->[1] = &parallel($this->[1], $reachingVals);
        my %savedReachingVals = %$reachingVals;
        my %thenReachingVals = %savedReachingVals;
        $this->[2] = &parallel($this->[2], \%thenReachingVals);
        my %elseReachingVals = %savedReachingVals;
        $this->[3] = &parallel($this->[3], \%elseReachingVals);
        foreach my $variable (uniq (keys %thenReachingVals, keys %elseReachingVals)) {
            my $thenval = $thenReachingVals{$variable} || &UNDEF();
            my $elseval = $elseReachingVals{$variable} || &UNDEF();
            $$reachingVals{$variable} = &SELECT($this->[1], $thenval, $elseval);
        }
    } else {
        @$this = map { &parallel($_, $reachingVals) } @$this;
    }
    return $this;
}

sub remove_dead_writes {
    my ($this) = @_;
    # Remove from THIS any WRITES to names that are not in LIVE_NAMES.
    return $this if ref $this ne 'ARRAY';
    @$this = map {
        &remove_dead_writes($_);
      } @$this;
    if ($this->[0] eq 'WRITE') {
        my $Section = $this->[1];
        my $Variable = $this->[2];
        my $parallel_reads = $parallel_reads{$Variable} || 0;
        if ($Section eq "" and $parallel_reads == 0) {
            return &SKIP();
        }
    }
    return $this;
}

sub propagate_conditions {
    my ($this, $true_conds, $false_conds) = @_;
    # Propagate conditions down the tree, resolving tests where possible.
    return $this if ref $this ne 'ARRAY';
    if ($this->[0] =~ /^(SELECT|IF)$/) {
        $this->[1] = &propagate_conditions($this->[1], $true_conds, $false_conds);
        my $test = $this->[1];
        push @$true_conds, $test;
        $this->[2] = &propagate_conditions($this->[2], $true_conds, $false_conds);
        pop @$true_conds;
        push @$false_conds, $test;
        $this->[3] = &propagate_conditions($this->[3], $true_conds, $false_conds);
        pop @$false_conds;
        foreach my $cond (@$true_conds) {
            return $this->[2] if (&Same($cond, $test));
        }
        foreach my $cond (@$false_conds) {
            return $this->[3] if (&Same($cond, $test));
        }
    } else {
        @$this = map { &propagate_conditions($_, $true_conds, $false_conds) } @$this;
    }
    return $this;
}

sub uniq {
    my %h;
    map { $h{$_}++; } @_;
    return keys %h;
}

#
# Infer the read/write action of each operand proxy (METHOD.%N) directly from the
# Behavior syntax tree, for the summary properties of Operator(s) and Parameter(s).
# This method will eventually go to Semantics.
#
# A single top-down traversal carries down the small context each METHOD leaf needs,
# so the tree is visited once (O(nodes)) with no path materialization.  It replaces
# the former Collate, which enumerated one full root-to-node path per node and then
# re-parsed those strings: Theta(nodes * depth) at best, and it re-traversed shared
# DAG subtrees once per incoming path (the Simplify SELECT-hoisting shares branch
# arms), so it could blow up superlinearly.  The four inference rules are matched
# structurally during descent instead:
#
#   * a METHOD in the location (array-child 0) of the nearest enclosing LOAD/STORE
#     is a Read/Write at that node's stage (nearest wins, so a deeper LOAD/STORE
#     overrides an outer one);
#   * else a METHOD whose nearest non-coercion parent is SX/ZX is a Read;
#   * else a METHOD naming an Immediate is a Read;
#   * else it is a direct use of METHOD in Behavior and is ignored.
#
# F2I/I2F/B2I/I2B coercion nodes are transparent to the SX/ZX-parent test and to the
# ancestor depth, exactly as the former path filtering made them.
#
# Returns { '%N' => { Read|Write => { STAGE => s } } }.
#
sub proxyActions {
    my ($tree, $proxyMethodID) = @_;
    my %action;
    &proxyActionsWalk($tree, $proxyMethodID, \%action, undef, undef, undef, 0);
    return \%action;
}

# $act/$stage: action+stage of the nearest enclosing LOAD/STORE location (undef if none).
# $parent:     label of the nearest non-coercion ancestor (undef at the root).
# $nca:        number of non-coercion ancestors (matches the former filtered path depth).
sub proxyActionsWalk {
    my ($tree, $proxyMethodID, $action, $act, $stage, $parent, $nca) = @_;
    return unless ref $tree eq 'ARRAY';
    my $label = join '.', grep { !ref } @{$tree};

    if ($label =~ /^METHOD\.(\%\d+(:\d+)?)$/) {
        my $proxy = $1;
        my $methodID = $$proxyMethodID{$proxy};
        if (defined $act) {
            $action->{$proxy}{$act}->{STAGE} = $stage;
        } elsif ($nca >= 2 && defined $parent && $parent =~ /^[SZ]X\b/) {
            $action->{$proxy}{Read}->{STAGE} = 0;
        } elsif (defined $methodID && $methodID =~ /^Immediate/) {
            $action->{$proxy}{Read}->{STAGE} = 0;
        } # Else a direct use of METHOD in Behavior, ignore.
        return;
    }

    # A LOAD.<stage>/STORE.<stage> hands its location (array-child 0) a Read/Write.
    my ($lsact, $lsstage);
    if ($label =~ /^(LOAD|STORE)\.(\d*)$/) {
        $lsact   = $1 eq 'STORE' ? 'Write' : 'Read';
        $lsstage = $2 || 0;
    }

    my $coercion    = ($label =~ /^(F2I|I2F|B2I|I2B)/);
    my $childparent = $coercion ? $parent : $label;
    my $childnca    = $coercion ? $nca : $nca + 1;

    my $arrayindex = 0;
    foreach my $child (@{$tree}) {
        next unless ref $child eq 'ARRAY';
        my ($ca, $cs) =
          (defined $lsact && $arrayindex == 0) ? ($lsact, $lsstage) : ($act, $stage);
        &proxyActionsWalk($child, $proxyMethodID, $action, $ca, $cs, $childparent, $childnca);
        $arrayindex++;
    }
}

#
# Pretty output of the syntax tree.
#
# $print_attributes selects what goes into the Abstract of each Integer/Boolean,
# the "(*key:value,...*)" the grammar parses back into that node's attribute hash:
#
#   0 or undef	no Abstract at all (the default, and what the tables held before
#		anything wrote abstract values into them).
#   a HASH ref	only the named keys, e.g. { lo=>1, hi=>1 }.  This is the useful
#		form: the attribute hash also carries the internal TYPE/WIDTH/REPR
#		and dumping those into every node would bloat the tables for
#		nothing.
#   any true	every non-ref key.  Debugging only.
#
# Only scalars are emitted -- a CODE ref cannot be spelled in the syntax, and a
# Math::BigInt is a blessed ref, so an abstract value has to be stringified by
# whoever stamps it (Width.pm does).
#
sub Pretty {
    my ($this, $spacing, $print_attributes) = @_;
    $spacing = "\t" unless defined $spacing;
    $print_attributes = 0 unless defined $print_attributes;
    my @result = ( "\n" );
    &pretty(\@result, $this, $spacing, 1, $print_attributes);
    push @result, "\n";
    return @result;
}

sub pretty {
    my ($pretty, $this, $spacing, $nesting, $print_attributes) = @_;
    my $omit_1 = $$this[0] =~ /\b(APPLY|READ|WRITE)\b/;
    my $indent = $spacing x $nesting;

    # BIND and APPLYT carry a LIST where every other node carries a scalar -- the bound
    # names, and the element widths.  The generic walk below would take each list for a
    # child node and emit "(BIND (a.b.c) ...)", which is not what the grammar reads, so
    # the tree would not survive the round trip through Opcode.table.  It does not fail
    # quietly: BE/LAO and MDD/MDE re-parse that file, and a malformed emission is a
    # syntax error there.  (Which is how this was found.)
    #
    # APPLYT prints as APPLY: the surface syntax distinguishes the two by the comma in
    # the width list, not by the keyword -- DOC/Behavior.y's Tuple production.  The node
    # name differs so that an unported consumer meets an unknown operator rather than a
    # scalar slot holding a ref; the printed form must not.
    if ($$this[0] eq 'BIND') {
        my ($names, $tuple) = @{$this}[1, 2];
        push @$pretty, "(BIND." . join(',', @{$names});
        push @$pretty, "\n", $indent;
        &pretty($pretty, $tuple, $spacing, $nesting + 1, $print_attributes);
        push @$pretty, ")";
        return;
    }
    if ($$this[0] eq 'APPLYT') {
        my ($widths, $name) = @{$this}[1, 2];
        push @$pretty, "(APPLY." . join(',', @{$widths}) . ".$name";
        foreach my $item (@{$this}[3 .. $#{$this}]) {
            next unless ref $item eq 'ARRAY';
            push @$pretty, "\n", $indent;
            &pretty($pretty, $item, $spacing, $nesting + 1, $print_attributes);
        }
        push @$pretty, ")";
        return;
    }

    # An operand-attributed Location (AGGL/AGGB with a proxy in slot 4) must
    # print as (AGGL.storage.proxy addr extent) so it re-parses through the
    # Location -> '(' AGGL '.' Storage '.' Proxy Address Extent ')' rule.  The
    # generic scalar walk below would emit the proxy as a trailing " %k", which
    # is not grammar and would not survive the Opcode.table round trip.
    if (($$this[0] eq 'AGGL' || $$this[0] eq 'AGGB') && defined $$this[4]) {
        push @$pretty, "($$this[0].$$this[1].$$this[4]";
        foreach my $item ($$this[2], $$this[3]) {
            push @$pretty, "\n", $indent;
            &pretty($pretty, $item, $spacing, $nesting + 1, $print_attributes);
        }
        push @$pretty, ")";
        return;
    }

    my $sep = "";
    push @$pretty, "(";
    my $index = 0;
    foreach my $item (@{$this}) {
        if (ref $item eq 'ARRAY') {
            my @items = @{$item};
            if ($items[0] eq 'SECTION') {
                push @$pretty, "." . $items[1] . "[";
                if (ref $items[2] eq 'ARRAY') {
                    &pretty($pretty, $items[2], $spacing, $nesting+1, $print_attributes);
                } else {
                    if (defined $items[2]) {
                        push @$pretty, $items[2];
                    } else {
                        push @$pretty, "0";
                    }
                }
                push @$pretty, "]";
                next
            }
            push @$pretty, "\n", $indent;
            # $print_attributes has to travel down: without it only the root node
            # could ever emit an Abstract, and the root is always a Command, which
            # has no attribute hash -- so nothing was ever emitted at all.
            &pretty($pretty, $item, $spacing, $nesting+1, $print_attributes);
            $sep = " ";
        } elsif ($print_attributes and ref $item eq 'HASH'
            and $$item{TYPE} =~ /^(Integer|Boolean)$/) {
            my @keys = grep {
                !ref $$item{$_}
                  && (ref $print_attributes ne 'HASH' || $print_attributes->{$_})
              } keys %{$item};
            if (@keys) {
                my $sep = '';
                push @$pretty, "(*";
                foreach my $key (sort @keys) {
                    push @$pretty, $sep, $key, ':', $$item{$key};
                    $sep = ',';
                }
                push @$pretty, "*)";
            }
        } elsif (!ref $item) {
            unless ($index == 1 && $omit_1 && !$item) {
                push @$pretty, $sep, $item;
                $sep = ".";
            }
        }
        $index++;
    }
    push @$pretty, ")";
}

#
# CodeGen output of the C like syntax tree.
#

my $CodeGen_Opcode;
my $CodeGen_Helpers;
my $CodeGen_Proxies;
my $CodeGen_Operands;
my $CodeGen_Statics;
my $CodeGen_Spacing;
# name => [ widths ], the tuple structs the emitted C needs a typedef for.  Optional, so
# a caller that predates tuples still works and simply cannot receive one -- there is no
# APPLYT without a BIND, and no BIND unless the description writes one.
my $CodeGen_Tuples;
# One temporary per BIND, holding the struct between the call and the destructuring.  FOR
# is unrolled here, so a bind in a lane body emits once per lane and each needs its own.
my $CodeGen_Binds;

sub CodeGen {
    my ($this, $_opcode, $_helpers, $_proxies, $_operands, $_statics, $_spacing,
        $_tuples) = @_;
    my @pretty = ( "\n" );
    my %context;
    $CodeGen_Opcode = $_opcode;
    $CodeGen_Helpers = $_helpers;
    $CodeGen_Proxies = $_proxies;
    $CodeGen_Operands = $_operands;
    $CodeGen_Statics = $_statics;
    $CodeGen_Tuples = $_tuples;
    $CodeGen_Binds = 0;
    $CodeGen_Spacing = $_spacing || "\t";
    &vartypes($this);
    &codegen($this, \@pretty, 1, \%context);
    $pretty[-1] .= ";";
    return @pretty;
}

sub signature {
    my ($this, $pretty, $nesting, $context) = @_;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    my $helper_name;
    my $first_arg_idx;
    my $return_type = 'void';
    if ($$this[0] eq "TEST") {
        $helper_name = $$this[1];
        $first_arg_idx = 2;
        $return_type = "bool";
    }
    elsif ($$this[0] eq "APPLY") {
        $helper_name = $$this[2];
        $first_arg_idx = 3;
        $return_type = "Int256_";
    }
    elsif ($$this[0] eq "APPLYT") {
        # A tuple-valued helper returns a small struct by value, one type per shape.  The
        # widths are on the node and the Helper element declares them too; Width.pm's
        # helper-result is what keeps the two agreeing, so this can trust either.
        $helper_name = $$this[2];
        $first_arg_idx = 3;
        my $widths = $$this[1];
        $return_type = &_ctype_tuple($widths);
        if (defined $CodeGen_Tuples && !defined $$CodeGen_Tuples{$return_type}) {
            # Hand back the rendered typedef, not the widths: the element types are
            # ctype's business and the consumer only has to print this.
            my $fields = '';
            for (my $i = 0; $i < @{$widths}; $i++) {
                $fields .= ' ' . &cdecl(&_ctype_element($widths->[$i])) . " _$i;";
            }
            $$CodeGen_Tuples{$return_type} = "typedef struct {$fields } $return_type;";
        }
    }
    elsif ($$this[0] eq "EFFECT") {
        $helper_name = $$this[2];
        $first_arg_idx = 3;
    }
    elsif ($$this[0] eq "THROW") {
        $helper_name = "throw_".$$this[2];
        $first_arg_idx = 3;
    }
    # Those 2 confess should be equivalent.
    confess "Unable to find helper_name for $$this[0]" unless defined $helper_name;
    confess "Unable to find first argument position for $$this[0]" unless defined $first_arg_idx;
    # The helper's declared signature, if it has one (DOC/MDD.dtd's Helper).  Without one
    # every argument is an Int256_, which is what they all were.
    my $arguments = $Signature{$helper_name}{arguments};
    if ($$this[0] eq "APPLY") {
        my $result = &_signature_result($helper_name);
        $return_type = &cdecl($result) if defined $result;
    }
    my $proto = "$return_type $helper_name(void *this";
    push @$pretty, "${indent}HELPER($helper_name)(this";
    my $opnd_id = 1;
    for (my $i = $first_arg_idx; $i < @$this; $i++) {
        if (not ref $$this[$i] eq "ARRAY")  {
            next;
        }
        if ($$this[$i][0] !~ /^UNDEF$/) {
            $$pretty[-1] .= ","; push(@$pretty, ${indent_incremented});
            my $want = &_signature_type($arguments, $opnd_id);
            &codegen_operand($$this[$i], $want, $pretty, $nesting + 1, $context);
            $proto .= ", " . &cdecl($want) . " opnd$opnd_id";
        }
        $opnd_id++;
    }
    $$pretty[-1] .= ")";
    $proto .= ");";
    if (!defined $$CodeGen_Helpers{$helper_name}) {
        $$CodeGen_Helpers{$helper_name} = $proto;
    }
    else {
        (my $restype_h = $$CodeGen_Helpers{$helper_name}) =~ s/^(\w+)\s+.*/$1/;
        (my $restype_p = $proto) =~ s/^(\w+)\s+.*/$1/;
        if ($restype_h ne 'void' && $restype_p ne 'void'
            && $$CodeGen_Helpers{$helper_name} ne $proto) {
            warn "Prototypes do not match for helper $helper_name" .
              "($$CodeGen_Helpers{$helper_name} != $proto)";
        }
    }
}

my %codegen_member = (
    1=> 'bits',
    8=> 'bytes',
    16=> 'hwords',
    32=> 'words',
    64=> 'dwords',
    128=> 'qwords',
  );

sub codegen_read {
    use integer;
    my ($section_ref, $context) = @_;
    my $need_conv = 1;
    my @section = @{$section_ref};
    my ($width, $index) = ($section[1], $section[2]);
    if (ref $index eq 'ARRAY') {
        my @idx = @{$index};
        my %cont = %{$context};
        if ($idx[0] eq 'INDEX') {
            $need_conv = 0;
            my $var = $idx[1];
            if (exists $cont{$var}) {
                $index = $cont{$var};
            } else {
                die "variable $var not bound";
            }
        }
    }
    die "Invalid READ section '@section'" unless defined $width and defined $index;
    die "Invalid READ width in '@section'" unless defined $codegen_member{$width};
 # die "Out-of-bounds READ index in '@section'" unless $width*($index+1) <= 256;
    my ($open, $close) = ('[', ']');
    my $codegen_access = $codegen_member{$width};
    if ($width < 8) {
        $open = '_';
        $close = '';
        $width = 8;
    }
    if (ref $index eq 'ARRAY') {
        my $res .= ".$codegen_access$open";
        my @pretty = ( "" );
        &codegen_boxed($index, \@pretty, 0, $context);
        $res .= "Int256_toUInt$width(" if $need_conv;
        $res .= join '', @pretty;
        $res .= ")" if $need_conv;
        $res .= "$close)";
        return ("Int256_fromUInt$width(", $res);
    } else {
        return ("Int256_fromUInt$width(", ".$codegen_access${open}$index${close})");
    }
}

sub codegen_write {
    use integer;
    my ($section_ref, $context) = @_;
    my @section = @{$section_ref};
    my $need_conv = 1;
    my ($width, $index) = ($section[1], $section[2]);
    if (ref $index eq 'ARRAY') {
        my @idx = @{$index};
        my %cont = %{$context};
        if ($idx[0] eq 'INDEX') {
            $need_conv = 0;
            my $var = $idx[1];
            if (exists $cont{$var}) {
                $index = $cont{$var};
            } else {
                die "variable $var not bound";
            }
        }
    }
    die "Invalid WRITE section '@section'" unless defined $width and defined $index;
    die "Invalid WRITE width in '@section'" unless defined $codegen_member{$width};
# die "Out-of-bounds WRITE index in '@section'" unless $width*($index+1) <= 256;
    my ($open, $close) = ('[', ']');
    my $codegen_access = $codegen_member{$width};
    if ($width < 8) {
        $open = '_';
        $close = '';
        $width = 8;
    }
    if (ref $index eq 'ARRAY') {
        my $res .= ".$codegen_access$open";
        my @pretty = ( "" );
        &codegen_boxed($index, \@pretty, 0, $context);
        $res .= "Int256_toUInt$width(" if $need_conv;
        $res .= join '', @pretty;
        $res .= ")" if $need_conv;
        $res .= "$close";
        return ($res, ".$codegen_access${open}0${close}");
    } else {
        return (".$codegen_access${open}$index${close}", ".$codegen_access${open}0${close}");
    }
}

sub codegen_mask {
    use integer;
    my ($prefix, $mask_ref) = @_;
    my @mask = @{$mask_ref};
    my @mask_value = ( 0, 0, 0, 0 );
    my ($width, $index) = ($mask[1], $mask[2]);
    die "Out-of-bounds SECTION index in '@mask'" unless $width*($index+1) <= 256;
    my $major = ($width*$index) / 64;
    my $minor = ($width*$index) % 64;
    my $ones = $width < 64? (1<<$width)-1: -1;
    $mask_value[$major] = sprintf("0x%016lx", $ones << $minor);
    my $mask_name = $prefix . join ('_', @mask_value);
    $mask_name =~ s/0x/_/g;
    return ($mask_name, \@mask_value);
}

################################################################################
#
# The type model: giving an Integer a native C type instead of an Int256_.
# DOC/Behavior.md section 6 is the argument; this is the implementation.
#
# Every Integer in the generated C is an Int256_ -- a 32-byte union passed by
# value, whose Int256_add is a four-limb do/while with branchy carry propagation
# and whose Int256_toUInt64 is just the low limb.  93% of them do not need to be.
# LIB/Width.pm published, on every Integer node, the interval it can hold (lo, hi)
# and how many of its low bits anyone looks at (dm); Opcode.table carries both, and
# the grammar parses them back into the node's attribute hash, so they are here to
# be read.  The usable width of a node is
#
#     min(bits its interval needs, bits anyone demands)
#
# and both halves are needed: addw's ADD of two 64-bit registers is [0, 2^65-2],
# which fits no native type, but only its low 32 bits are ever stored, so it is a
# uint32_t.
#
# A node of width W is held in a uint<W>_t containing its value modulo 2^W.  It is
# EXACT when its interval fits in W bits -- then the mathematical value can be
# recovered from the bits, read signed or unsigned as the interval says.
#
# THE RULE IS NOT UNIFORM ACROSS OPERATORS, and this is the trap.  "A node whose
# demand is d can be computed in a d-bit type" holds because the ring operations
# (+ - * << & | ^ ~) agree with the true result on their low d bits -- they commute
# with truncation.  SHR does not.  It reads the value, not its low bits, and
# Width.pm's own _shr says so: on an operand that is not provably non-negative it
# gives up and returns the interval of a logical shift of the whole container.
#
# sraw is (SHR (SX.32 x) n) with dm 32, so min(rep, dm) would make it a uint32_t
# and a uint32_t `>>` is a LOGICAL shift -- while the semantics is a logical shift
# of the value sign-extended across the 256-bit container, whose low 32 bits are an
# ARITHMETIC shift.  For x = 0x80000000, n = 4 that is 0x08000000 against the
# correct 0xf8000000.  All 89 shr-negative sites (sraw/srad/srsw/srsd/avgw/extfs/
# sxbd/...) break, silently and only in the sign bits.
#
# So SHR is typed by its demand like a ring operation, but EMITTED as an arithmetic
# shift whenever its operand's reading is signed.  That is sound precisely because
# the operand is exact: _dexpr demands d + shift bits of it, so its width is its
# interval's, and sign-extending it to any width recovers the true value.
#
# Everything else that reads a value rather than its low bits -- DIV/REM/MOD, the
# comparisons, MIN/MAX, SAT, the bit counters -- gets exact operands for free:
# _dexpr demands the whole value from them, so min(rep, dm) is rep.
#
our $Unbox = 0;			# BE/LAO/BIN/Behavior.pl sets it; off = the old generator

my $BOX = 256;

# The C type of a declared width, or undef if the helper declared none.  A width of 256 is
# the container, and saying so is the same as saying nothing.
sub _signature_type {
    my ($widths, $position) = @_;
    return &_ctype_box() unless ref $widths eq 'ARRAY';
    my $width = $widths->[$position - 1];
    return &_ctype_box() unless defined $width && $width > 0 && $width <= 128;
    return { W => &_ctype_native($width), S => 0, E => 1 };
}

sub _signature_result {
    my ($name) = @_;
    my $result = $Signature{$name}{result};
    return undef unless ref $result eq 'ARRAY';
    # This types an APPLY, which is single-valued.  A tuple-valued declaration belongs to
    # an APPLYT, whose elements are typed one at a time; reaching here with one means the
    # declaration and the call site disagree, which Width.pm reports as helper-result and
    # fails the build for.  Decline to type it rather than guess which element was meant.
    return undef unless @{$result} == 1;
    my $width = $result->[0];
    return &_ctype_box() if $width > 128;
    return { W => &_ctype_native($width), S => 0, E => 1 };
}

# The ring operations, and only these, may be computed in fewer bits than their
# interval needs.  SELECT is here because it merely chooses between its arms.
my %CodeGen_Ring = map { ($_ => 1) } qw(ADD SUB MUL AND IOR XOR NOT NEG SHL SELECT);

# The operators codegen can emit natively.  Anything else stays an Int256_, and its
# operands are converted back to Int256_ at the boundary -- which is what makes this
# safe to land incrementally: an operator not named here simply does not unbox.
# THIS MUST NAME EXACTLY WHAT codegen EMITS NATIVELY.  ctype is what the consumers
# believe; the emission is what they get, and a name in here without the matching
# case below is a type lie that the C compiler will not catch.
my %CodeGen_Native = map { ($_ => 1) } qw(
  SHR SX ZX F2I CONST READ
  ADD SUB MUL AND IOR XOR NOT NEG SHL SELECT
  METHOD MIN MAX CLZ CLS CTZ CBS
);

# A variable's C type.  It is the type of what is written to it -- which is what makes
# addw's result1 a uint32_t: its WRITE's right-hand side is the ADD whose demand is 32.
# A variable touched through a Section is a vector (the lanes are .words[i] of the
# container), so it stays an Int256_; so does one whose writes disagree, which is the
# conservative reading of a variable written under an IF.
my %CodeGen_VarTypes;

sub vartypes {
    my ($this) = @_;
    %CodeGen_VarTypes = ();
    return unless $Unbox;
    # Three passes, and the order is not cosmetic.  A variable's type has to be settled
    # before any ctype() that depends on it is asked for, and a lane access anywhere in
    # the tree pins the variable to the container -- including one that appears after
    # the WRITE whose right-hand side would otherwise have typed it.  Binds go before
    # writes for the same reason a write's own join exists: a name that is bound in one
    # place and written in another takes the container unless the two agree, and that
    # cannot be decided until both have been seen.
    &_vartypes_lanes($this);
    &_vartypes_binds($this);
    &_vartypes_writes($this);
}

sub _vartypes_lanes {
    my ($this) = @_;
    return unless ref $this eq 'ARRAY' && defined $$this[0] && !ref $$this[0];
    my $operator = $$this[0];
    if (($operator eq 'WRITE' || $operator eq 'READ') && $$this[1]) {
        $CodeGen_VarTypes{$$this[2]} = &_ctype_box();
    }
    foreach my $child (@$this) {
        &_vartypes_lanes($child) if ref $child eq 'ARRAY';
    }
}

# The C type of one element of a tuple, and of the tuple itself.  The element type is the
# element's declared width, exactly as _signature_result types an APPLY's single result;
# the struct's name is a function of the widths, so it is shared by shape rather than by
# helper -- f32_add, f32_sub and f32_mul all return Tuple_32_5.
sub _ctype_element {
    my ($width) = @_;
    return &_ctype_box() if $width > 128;
    return { W => &_ctype_native($width), S => 0, E => 1 };
}

sub _ctype_tuple {
    my ($widths) = @_;
    return 'Tuple_' . join('_', @{$widths});
}

sub _vartypes_binds {
    my ($this) = @_;
    return unless ref $this eq 'ARRAY' && defined $$this[0] && !ref $$this[0];
    if ($$this[0] eq 'BIND') {
        # A bound name has no WRITE to be typed from -- its type is its element's declared
        # width.  Same join as a WRITE's: a name bound in one place and written in another
        # keeps the container unless the two agree.
        my ($names, $tuple) = @{$this}[1, 2];
        my $widths = $$tuple[1];
        for (my $i = 0; $i < @{$names}; $i++) {
            my $name = $names->[$i];
            my $known = $CodeGen_VarTypes{$name};
            next if defined $known && $$known{W} == $BOX;
            my $type = &_ctype_element($widths->[$i]);
            $CodeGen_VarTypes{$name} =
              (!defined $known)             ? $type
              : &_ctype_same($known, $type) ? $known
              :                               &_ctype_box();
        }
    }
    foreach my $child (@$this) {
        &_vartypes_binds($child) if ref $child eq 'ARRAY';
    }
}

sub _vartypes_writes {
    my ($this) = @_;
    return unless ref $this eq 'ARRAY' && defined $$this[0] && !ref $$this[0];
    if ($$this[0] eq 'WRITE' && !$$this[1]) {
        my ($Variable, $Integer) = @{$this}[2, 3];
        my $known = $CodeGen_VarTypes{$Variable};
        unless (defined $known && $$known{W} == $BOX) {
            my $type = &ctype($Integer);
            $CodeGen_VarTypes{$Variable} =
              (!defined $known)             ? $type
              : &_ctype_same($known, $type) ? $known
              :                               &_ctype_box();
        }
    }
    foreach my $child (@$this) {
        &_vartypes_writes($child) if ref $child eq 'ARRAY';
    }
}

sub _ctype_box { return { W => $BOX, S => 1, E => 1 }; }

sub _ctype_native {		# the native width holding $bits
    my ($bits) = @_;
    foreach my $w (8, 16, 32, 64, 128) {
        return $w if $bits <= $w;
    }
    return $BOX;
}

sub _ctype_shift {		# the largest a shift amount can be, or undef
    my ($this) = @_;
    return undef unless ref $this eq 'ARRAY';
    # A CONST carries no interval -- its value is right there, and a constant shift
    # amount is much the commonest kind.  Without this every `<< 32` stays boxed.
    return $$this[1] if $$this[0] eq 'CONST' && $$this[1] =~ /^\d+$/;
    return undef unless ref $$this[-1] eq 'HASH';
    return $$this[-1]{hi};
}

# The width a ring operation is computed in.  It is at least 32 because uint8_t and
# uint16_t promote to *int*, and a 16x16 MUL overflows it -- signed overflow being
# undefined where the boxed code had none.  Any width at or above the result's will
# do: a ring operation's low W bits depend only on its operands' low W bits, which is
# what lets the operands carry garbage above W and the result be truncated back.
sub _ctype_ring {
    my ($width, $atleast) = @_;
    $atleast = 32 unless defined $atleast;
    my $M = $width > $atleast ? $width : $atleast;
    return &_ctype_native($M);
}

sub _ctype_bounds {		# a node's interval, or (undef, undef)
    my ($this) = @_;
    return (undef, undef) unless ref $this eq 'ARRAY';
    if ($$this[0] eq 'CONST') {
        return ($$this[1], $$this[1]) if $$this[1] =~ /^-?\d+$/;
        return (undef, undef);
    }
    return (undef, undef) unless ref $$this[-1] eq 'HASH';
    return ($$this[-1]{lo}, $$this[-1]{hi});
}

# The type two operands must both be read in to be COMPARED -- the minimal one holding
# the union of their intervals, and the signedness that union has to be read with.
# Int256_cmp orders sign-extended 256-bit values, so this has to reproduce the ordering
# of the mathematical values, not of their low bits: a common type and one signedness.
#
# The operands are exact, whatever their own ctype says: _dexpr demands the whole value
# from a comparison's operands, so their width is their interval's.  That is what lets a
# boxed operand be compared natively too -- its low W bits are its value, and W is wide
# enough for both by construction.
sub _ctype_join {
    my ($a, $b) = @_;
    return undef unless $Unbox;
    my ($lo1, $hi1) = &_ctype_bounds($a);
    my ($lo2, $hi2) = &_ctype_bounds($b);
    return undef unless defined $lo1 && defined $hi1 && defined $lo2 && defined $hi2;
    my ($lo, $hi) = (Math::BigInt->new("$lo1"), Math::BigInt->new("$hi1"));
    my $l2 = Math::BigInt->new("$lo2");
    my $h2 = Math::BigInt->new("$hi2");
    $lo = $l2 if $l2 < $lo;
    $hi = $h2 if $h2 > $hi;
    my ($W, $S) = &_ctype_rep($lo, $hi);
    return undef if $W > 64;
    return { W => $W, S => $S, E => 1 };
}

sub _ctype_mask {		# the low-$bits mask, as a literal of the type it masks
    my ($bits, $width) = @_;
    my $mask = Math::BigInt->new(2)->bpow($bits)->bsub(1);
    return "UINT64_C($mask)" if $width == 64;
    return "(uint${width}_t)UINT64_C($mask)";
}

# The minimal native width holding [lo,hi], and whether the bits must be read as
# signed to recover the value.  A full-width unsigned datum is representable and is
# simply not a signed number -- that distinction is Width.pm's, and it matters here
# because it decides the C type a value-reading operator sees.
sub _ctype_rep {
    my ($lo, $hi) = @_;
    return ($BOX, 1) unless defined $lo && defined $hi;
    $lo = Math::BigInt->new("$lo");
    $hi = Math::BigInt->new("$hi");
    foreach my $w (8, 16, 32, 64, 128) {
        my $top = Math::BigInt->new(2)->bpow($w);
        my $half = $top->copy()->bdiv(2);
        return ($w, 0) if $lo >= 0 && $hi < $top;
        return ($w, 1) if $lo >= -$half && $hi < $half;
    }
    return ($BOX, ($lo < 0) ? 1 : 0);
}

# The C type of an Integer node, from the abstract values on it.
sub ctype {
    my ($this) = @_;
    return _ctype_box() unless ref $this eq 'ARRAY' && defined $$this[0];
    my $operator = $$this[0];

    # A helper's declared result applies whether or not the arithmetic is unboxed: the
    # emission of an APPLY *is* the call, and the call returns what the signature says it
    # returns.  The calling convention and the arithmetic are separate concerns, and
    # keeping them separate is what makes the change checkable -- a boxed tuple built with
    # the signatures and an unboxed one built with the same signatures share an ABI, so
    # their traces can be compared.
    if ($operator eq 'APPLY') {
        my $result = &_signature_result($$this[2]);
        return defined $result ? $result : _ctype_box();
    }

    return _ctype_box() unless $Unbox;
    return _ctype_box() unless $CodeGen_Native{$operator};

    # A coercion whose width has no native type (SX.128, ZX.256, F2I.256 -- the XVR
    # octuples) has nothing to extend into or mask against, whatever its interval says.
    return _ctype_box()
      if $operator =~ /^(SX|ZX|F2I)$/ && $$this[1] > 64;

    my ($lo, $hi, $dm);
    if ($operator eq 'CONST') {
        # A CONST carries no interval: its value is right there.  A symbolic one is
        # an enum member of unknown value, so it does not unbox.
        return _ctype_box() unless $$this[1] =~ /^[\-0-9]+$/;
        ($lo, $hi) = ($$this[1], $$this[1]);
    } elsif ($operator eq 'READ') {
        # The emission of a plain READ *is* the variable, so its type is the
        # variable's, not whatever this particular read happens to demand.  (It can
        # only ever demand less: the variable's demand is the largest over its reads.)
        return _ctype_box() if $$this[1];		# a lane of the container
        my $type = $CodeGen_VarTypes{$$this[2]};
        return defined $type ? $type : _ctype_box();
    } elsif ($operator eq 'APPLY') {
        # An APPLY is whatever its helper RETURNS -- the emission is the call, so the type
        # is the declared result and nothing else.  A helper that declares none keeps the
        # container, which is what every one of them used to return.
        my $result = &_signature_result($$this[2]);
        return _ctype_box() unless defined $result;
        return $result;

    } elsif ($operator eq 'SHL') {
        # `x << n` with n at or past the width of x is undefined in C, where
        # Int256_shl merely shifts everything out and gives zero.  The shift is done
        # in a type wide enough to hold the largest amount (see codegen), so all this
        # has to rule out is an amount that no native type can take.
        my $bound = &_ctype_shift($$this[2]);
        return _ctype_box() unless defined $bound && $bound < 64;
        my $attributes = $$this[-1];
        return _ctype_box() unless ref $attributes eq 'HASH';
        ($lo, $hi, $dm) = @{$attributes}{qw(lo hi dm)};
    } elsif ($operator eq 'SHR') {
        # SHR is typed by its demand like a ring operation, but only because it is
        # emitted as an arithmetic shift when its operand is signed -- see codegen.
        # That needs the operand natively, and needs the shift amount to stay inside
        # the C type, since `x >> n` with n at or past the width is undefined where
        # Int256_shru simply gives zero.
        my $value = &ctype($$this[1]);
        # Exactness is the whole justification: sign-extending the operand to any
        # width recovers the true value only because its width is its interval's.
        return _ctype_box() if $$value{W} == $BOX || !$$value{E};
        my $bound = &_ctype_shift($$this[2]);
        return _ctype_box() unless defined $bound && $bound < $$value{W};
        my $attributes = $$this[-1];
        return _ctype_box() unless ref $attributes eq 'HASH';
        ($lo, $hi, $dm) = @{$attributes}{qw(lo hi dm)};
    } else {
        my $attributes = $$this[-1];
        return _ctype_box() unless ref $attributes eq 'HASH';
        ($lo, $hi, $dm) = @{$attributes}{qw(lo hi dm)};
    }
    $dm = $BOX unless defined $dm;

    my ($rep, $signed) = _ctype_rep($lo, $hi);
    my $width = $rep;
    if ($CodeGen_Ring{$operator} || $operator eq 'SHR') {
        # Truncation-safe: computing modulo 2^dm agrees on every bit anyone reads.
        $width = $dm if $dm < $rep;
    }
    return _ctype_box() if $width > 128;

    foreach my $w (8, 16, 32, 64, 128) {
        next if $w < $width;
        # Exact when the interval still fits after the demand narrowed it: only then
        # is the mathematical value recoverable from the bits.
        return { W => $w, S => $signed, E => ($rep <= $w ? 1 : 0) };
    }
    return _ctype_box();
}

sub cdecl {
    my ($type) = @_;
    return $$type{W} == $BOX ? "Int256_" : "uint$$type{W}_t";
}

sub _ctype_same {
    my ($a, $b) = @_;
    return $$a{W} == $$b{W} && $$a{S} == $$b{S};
}

# The conversion wrapping a subexpression of type $from where $to is wanted.
# Returned as (prefix, suffix) so it can bracket the existing push-based emission.
sub cconv {
    my ($from, $to) = @_;
    return ('', '') if $$from{W} == $$to{W};

    if ($$from{W} == $BOX) {			# Int256_ -> native: take the low limb
        my $w = $$to{W};
        # 128 has no Int256_toUInt128; the low 128 bits are the first qword of the union.
        return ("(", ").qwords[0]") if $w == 128;
        return ($w == 64 ? "Int256_toUInt64(" : "(uint${w}_t)Int256_toUInt64(", ")");
    }
    if ($$to{W} == $BOX) {			# native -> Int256_
        # An exact signed value must be sign-extended into the container, or the
        # Int256_ holds a large positive number instead of a negative one, and every
        # operator that reads the sign misreads it.
        # 128 has no Int256_fromInt128 taking a native, so box the bits with
        # fromUInt128 and sign-extend from bit 128 when the reading is signed.
        if ($$from{W} == 128) {
            return $$from{S} && $$from{E}
                ? ("Int256_sx(Int256_fromUInt128((uint128_t)(", ")), 128)")
                : ("Int256_fromUInt128((uint128_t)(", "))");
        }
        return ($$from{S} && $$from{E}
                ? "Int256_fromInt64((int64_t)(int$$from{W}_t)("
                : "Int256_fromUInt64((uint64_t)(", "))");
    }
    if ($$to{W} < $$from{W}) {			# narrowing: keep the low bits
        return ("(uint$$to{W}_t)(", ")");
    }
    # Widening.  The operand is exact here (a node narrower than its consumer wants
    # can only be one whose interval fits -- an inexact node's width is its demand,
    # which is at least its consumer's), so sign- or zero-extend by its reading.
    return ($$from{S} && $$from{E}
            ? "(uint$$to{W}_t)(int$$to{W}_t)(int$$from{W}_t)("
            : "(uint$$to{W}_t)(", ")");
}

# Emit a subexpression, converted to the type its consumer wants.
sub codegen_operand {
    my ($this, $want, $pretty, $nesting, $context) = @_;
    # Not gated on $Unbox: with the arithmetic boxed and a helper signature declared, the
    # operand is an Int256_ and the argument is a uint32_t, and that conversion still has
    # to happen.  With nothing declared every want is the container and this is a no-op.
    my $have = &ctype($this);
    my ($prefix, $suffix) = &cconv($have, $want);
    push(@$pretty, $prefix) if $prefix ne '';
    &codegen($this, $pretty, $nesting, $context);
    push(@$pretty, $suffix) if $suffix ne '';
}

# An operand of an operator that has not been unboxed: it wants an Int256_.  Every
# recursive emission in codegen goes through here, so a boxed operator keeps working
# unchanged while its operands may be computed natively and converted at the edge.
# It is a no-op with the gate off, and a no-op for Booleans, BitFields and commands,
# whose ctype is the box anyway.
sub codegen_boxed {
    my ($this, $pretty, $nesting, $context) = @_;
    return &codegen_operand($this, &_ctype_box(), $pretty, $nesting, $context);
}

# A binary ring operation, computed in $M bits and truncated back to its own width.
# Returns false if it does not unbox, leaving the caller to emit the Int256_ form.
sub codegen_ring2 {
    my ($this, $operator, $pretty, $nesting, $context) = @_;
    my $type = &ctype($this);
    return 0 if $$type{W} == $BOX;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    my ($W, $M) = ($$type{W}, &_ctype_ring($$type{W}));
    push(@$pretty, "${indent}(uint${W}_t)((uint${M}_t)(");
    &codegen_operand($$this[1], { W=>$M, S=>0, E=>0 }, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent_incremented}) $operator (uint${M}_t)(");
    &codegen_operand($$this[2], { W=>$M, S=>0, E=>0 }, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent}))");
    return 1;
}

# A comparison, in the common type its two operands have to be read in.  The result is a
# C bool, exactly as Int256_cmp(...) <op> 0 was, so nothing downstream changes.
sub codegen_compare {
    my ($this, $operator, $pretty, $nesting, $context) = @_;
    my $type = &_ctype_join($$this[1], $$this[2]);
    return 0 unless defined $type;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    my $C = $$type{S} ? "int$$type{W}_t" : "uint$$type{W}_t";
    push(@$pretty, "${indent}(($C)(");
    &codegen_operand($$this[1], $type, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent_incremented}) $operator ($C)(");
    &codegen_operand($$this[2], $type, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent}))");
    return 1;
}

# MIN/MAX: the comparison in the operands' common type, the result in its own.  The two
# operands are emitted twice each, in the same order the Int256_cmp form emitted them --
# a helper call in an operand happens as many times, and in the same sequence, as before.
sub codegen_minmax {
    my ($this, $first, $pretty, $nesting, $context) = @_;
    my $type = &ctype($this);
    my $join = &_ctype_join($$this[1], $$this[2]);
    return 0 if $$type{W} == $BOX || !defined $join;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    my $C = $$join{S} ? "int$$join{W}_t" : "uint$$join{W}_t";
    my ($then, $else) = $first ? (1, 2) : (2, 1);
    push(@$pretty, "${indent}(uint$$type{W}_t)((($C)(");
    &codegen_operand($$this[1], $join, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent_incremented}) > ($C)(");
    &codegen_operand($$this[2], $join, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent}))");
    push(@$pretty, "${indent}?");
    &codegen_operand($$this[$then], $type, $pretty, $nesting, $context);
    push(@$pretty, "${indent}:");
    &codegen_operand($$this[$else], $type, $pretty, $nesting, $context);
    push(@$pretty, ")");
    return 1;
}

# CLZ/CLS/CTZ/CBS: the count is small, so only the Int256_fromUInt32 wrapper goes.  The
# operand keeps the container -- the count is defined over the coercion width, and the
# runtime already does it.
sub codegen_count {
    my ($this, $routine, $pretty, $nesting, $context) = @_;
    my $type = &ctype($this);
    return 0 if $$type{W} == $BOX;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    push(@$pretty, "${indent}(uint$$type{W}_t)$routine(");
    &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent_incremented}, $$this[1]");
    push(@$pretty, "${indent})");
    return 1;
}

sub codegen_ring1 {
    my ($this, $operator, $pretty, $nesting, $context) = @_;
    my $type = &ctype($this);
    return 0 if $$type{W} == $BOX;
    my $indent = $CodeGen_Spacing x $nesting;
    my ($W, $M) = ($$type{W}, &_ctype_ring($$type{W}));
    push(@$pretty, "${indent}(uint${W}_t)($operator (uint${M}_t)(");
    &codegen_operand($$this[1], { W=>$M, S=>0, E=>0 }, $pretty, $nesting + 1, $context);
    push(@$pretty, "${indent}))");
    return 1;
}

sub codegen {
    use integer;
    my ($this, $pretty, $nesting, $context) = @_;
    my $indent = $CodeGen_Spacing x $nesting;
    my $indent_incremented = $indent . $CodeGen_Spacing;
    &confess("Undefined operator") if (!defined $$this[0]);
    SWITCH: {
        $$this[0] =~ /^SX$/ and do {
            # SX Constant Integer
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                # Sign-extend bit w-1 of the operand.  w is not always a native width
                # (SX.29 exists), so it is done with a pair of shifts in a type wide
                # enough to hold both the operand and the result.
                my $w = $$this[1];
                my $M = &_ctype_native($$type{W} > $w ? $$type{W} : $w);
                push(@$pretty, "${indent}(uint$$type{W}_t)((int${M}_t)((uint${M}_t)(");
                &codegen_operand($$this[2], { W=>$M, S=>0, E=>0 },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}) << " . ($M - $w) . ") >> " . ($M - $w));
                push(@$pretty, "${indent})");
                last SWITCH;
            }
            push(@$pretty, "${indent}Int256_sx(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^F2I$/ and do {
            # F2I Extent BitField
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                # The BitField is an Int256_ (a LOAD, or an I2F); take its low bits.
                my $M = &_ctype_native($$type{W} > $$this[1] ? $$type{W} : $$this[1]);
                push(@$pretty, "${indent}(uint$$type{W}_t)(Int256_toUInt64(");
                &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}) & " . &_ctype_mask($$this[1], $M));
                push(@$pretty, "${indent})");
                last SWITCH;
            }
            push(@$pretty, "${indent}Int256_zx(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^I2F$/ and do {
            # I2F Extent Integer
            push(@$pretty, "${indent}Int256_zx(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^I2B$/ and do {
            # I2B Integer
            push(@$pretty, "${indent}Int256_toBool(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^B2I$/ and do {
            # B2I Boolean
            push(@$pretty, "${indent}Int256_fromBool(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^ZX$/ and do {
            # ZX Constant Integer
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                my $w = $$this[1];
                my $M = &_ctype_native($$type{W} > $w ? $$type{W} : $w);
                push(@$pretty, "${indent}(uint$$type{W}_t)((uint${M}_t)(");
                &codegen_operand($$this[2], { W=>$M, S=>0, E=>0 },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}) & " . &_ctype_mask($w, $M));
                push(@$pretty, "${indent})");
                last SWITCH;
            }
            push(@$pretty, "${indent}Int256_zx(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SAT$/ and do {
            # SAT Constant Integer 
            push(@$pretty, "${indent}Int256_sat(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}, $$this[1])");
            last SWITCH;
          };
        $$this[0] =~ /^SATU$/ and do {
            # SATU Constant Integer 
            push(@$pretty, "${indent}Int256_satu(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}, $$this[1])");
            last SWITCH;
          };
        $$this[0] =~ /^CLZ$/ and do {
# CLZ Constant Integer 
# Count Leading Zero: CLZ.8 00010011 = 3, CLZ.8 00000000 = 8, CLZ.8 11111111 = 0
            last SWITCH if &codegen_count($this, 'Int256_clz', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_fromUInt32(Int256_clz(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent}))");
            last SWITCH;
          };
        $$this[0] =~ /^CLS$/ and do {
# CLS Constant Integer 
# Count Leading Sign: CLS.8 00010011 = 2, CLS.8 11110011 = 3, CLS.8 00000000 = 7, CLS.8 11111111 = 7
            last SWITCH if &codegen_count($this, 'Int256_cls', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_fromUInt32(Int256_cls(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent}))");
            last SWITCH;
          };
        $$this[0] =~ /^CTZ$/ and do {
# CTZ Constant Integer 
# Count Trailing Zero: CTZ.8 01001100 = 2, CTZ.8 00000000 = 8, CTZ.8 11111111 = 0
            last SWITCH if &codegen_count($this, 'Int256_ctz', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_fromUInt32(Int256_ctz(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent}))");
            last SWITCH;
          };
        $$this[0] =~ /^CBS$/ and do {
            # CBS Constant Integer 
            # Count Bit Set (Population count)
            last SWITCH if &codegen_count($this, 'Int256_cbs', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_fromUInt32(Int256_cbs(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent}))");
            last SWITCH;
          };
        $$this[0] =~ /^SWAP$/ and do {
            # SWAP Constant Integer
            push(@$pretty, "${indent}Int256_swap(");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, $$this[1]");
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^ROR$/ and do {
            # ROR Constant Integer Integer
            push(@$pretty, "${indent}Int256_ror(");
            push(@$pretty, "${indent_incremented}$$this[1], ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[3], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^ROL$/ and do {
            # ROL Constant Integer Integer
            push(@$pretty, "${indent}Int256_rol(");
            push(@$pretty, "${indent_incremented}$$this[1], ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[3], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^IORL$/ and do {
            push(@$pretty, "${indent}(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented} || ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^ANDL$/ and do {
            push(@$pretty, "${indent}(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented} && ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^XORL$/ and do {
            # $$this[0] Boolean Boolean
            push(@$pretty, "${indent}(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented} ^ ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^NOTL$/ and do {
            # NOTL Boolean
            push(@$pretty, "${indent}!(");
            &codegen_boxed($$this[1], $pretty, $nesting, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^NOT$/ and do {
            # NOT Integer
            last SWITCH if &codegen_ring1($this, '~', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_not(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^NEG$/ and do {
            # NEG Integer
            last SWITCH if &codegen_ring1($this, '-', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_neg(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^ABS$/ and do {
            # ABS Integer
            push(@$pretty, "${indent}Int256_abs(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SELECT$/ and do {
            # SELECT Boolean IntegerTrue IntegerFalse
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                push(@$pretty, "${indent}(uint$$type{W}_t)(");
                &codegen_boxed($$this[1], $pretty, $nesting, $context);
                push(@$pretty, "${indent}?");
                &codegen_operand($$this[2], $type, $pretty, $nesting, $context);
                push(@$pretty, "${indent}:");
                &codegen_operand($$this[3], $type, $pretty, $nesting, $context);
                push(@$pretty, ")");
                last SWITCH;
            }
            push(@$pretty, "(");
            &codegen_boxed($$this[1], $pretty, $nesting, $context);
            push(@$pretty, "${indent}?");
            &codegen_boxed($$this[2], $pretty, $nesting, $context);
            push(@$pretty, "${indent}:");
            &codegen_boxed($$this[3], $pretty, $nesting, $context);
            push(@$pretty, ")");
            last SWITCH;
          };
        $$this[0] =~ /^ADD$/ and do {
            last SWITCH if &codegen_ring2($this, '+', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_add(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SUB$/ and do {
            last SWITCH if &codegen_ring2($this, '-', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_sub(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^AND$/ and do {
            last SWITCH if &codegen_ring2($this, '&', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_and(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^IOR$/ and do {
            last SWITCH if &codegen_ring2($this, '|', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_or(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^XOR$/ and do {
            last SWITCH if &codegen_ring2($this, '^', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_xor(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^MUL$/ and do {
            last SWITCH if &codegen_ring2($this, '*', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_mul(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SHR$/ and do {
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                # THE one that is not a ring operation.  Int256_shru is a *logical*
                # shift of the 256-bit container, so on a negative operand it shifts
                # in the sign bits the container was extended with -- which is why
                # sraw = (SHR (SX.32 x) n) comes out right.  A uint32_t `>>` would
                # shift in zeros and quietly lose every sign bit.  The operand is
                # exact here (ctype boxed it otherwise), so its sign extension into
                # the shift's type recovers the true value, and the shift becomes an
                # ARITHMETIC one exactly when the operand's reading is signed.
                my $value = &ctype($$this[1]);
                my $M = &_ctype_native($$type{W} > $$value{W} ? $$type{W} : $$value{W});
                my $signed = $$value{S};
                push(@$pretty, "${indent}(uint$$type{W}_t)((" .
                     ($signed ? "int${M}_t" : "uint${M}_t") . ")(");
                &codegen_operand($$this[1], { W=>$M, S=>$$value{S}, E=>$$value{E} },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}) >> (");
                &codegen_operand($$this[2], { W=>8, S=>0, E=>1 },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent}))");
                last SWITCH;
            }
            # Int256_shr is an ARITHMETIC shift, Int256_shru a logical one.  Pick
            # by the operand's reading, exactly as the native path above does, so
            # the boxed and unboxed generations agree.  Neither depends on the
            # container width: arithmetic is floor(x/2^n) for any x, and logical on
            # a non-negative operand equals it.  This retires the box dependence
            # DOC/Behavior.md section 3 recorded for sraw and its family (the two
            # functions differ only in bits above the demand).  See DOC/SHR-split.md.
            my $shrvalue = &ctype($$this[1]);
            my $shrfn = $$shrvalue{S} ? 'Int256_shr' : 'Int256_shru';
            push(@$pretty, "${indent}${shrfn}(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SHL$/ and do {
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                # Shifted in a type that can take the largest amount, then truncated:
                # `x << n` is undefined in C once n reaches the width, and the low bits
                # of the result are the same whatever wider type it is computed in.
                my $bound = &_ctype_shift($$this[2]);
                my $W = $$type{W};
                my $M = &_ctype_ring($W, $bound + 1);
                push(@$pretty, "${indent}(uint${W}_t)((uint${M}_t)(");
                &codegen_operand($$this[1], { W=>$M, S=>0, E=>0 },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}) << (");
                &codegen_operand($$this[2], { W=>8, S=>0, E=>1 },
                                 $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent}))");
                last SWITCH;
            }
            push(@$pretty, "${indent}Int256_shl(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^DIV$/ and do {
            push(@$pretty, "${indent}Int256_div(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^REM$/ and do {
            # $$this[0] Integer Integer
            push(@$pretty, "${indent}Int256_rem(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^MOD$/ and do {
            # $$this[0] Integer Integer
            push(@$pretty, "${indent}Int256_mod(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^MIN$/ and do {
            # MIN Integer Integer
            last SWITCH if &codegen_minmax($this, 0, $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) > 0");
            push(@$pretty, "${indent}?");
            &codegen_boxed($$this[2], $pretty, $nesting, $context);
            push(@$pretty, "${indent}:");
            &codegen_boxed($$this[1], $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^MAX$/ and do {
            # MAX Integer Integer
            last SWITCH if &codegen_minmax($this, 1, $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) > 0");
            push(@$pretty, "${indent}?");
            &codegen_boxed($$this[1], $pretty, $nesting, $context);
            push(@$pretty, "${indent}:");
            &codegen_boxed($$this[2], $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^NE$/ and do {
            last SWITCH if &codegen_compare($this, '!=', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) != 0");
            last SWITCH;
          };
        $$this[0] =~ /^EQ$/ and do {
            last SWITCH if &codegen_compare($this, '==', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) == 0");
            last SWITCH;
          };
        $$this[0] =~ /^GT$/ and do {
            last SWITCH if &codegen_compare($this, '>', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) > 0");
            last SWITCH;
          };
        $$this[0] =~ /^LT$/ and do {
            last SWITCH if &codegen_compare($this, '<', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) < 0");
            last SWITCH;
          };
        $$this[0] =~ /^GE$/ and do {
            last SWITCH if &codegen_compare($this, '>=', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) >= 0");
            last SWITCH;
          };
        $$this[0] =~ /^LE$/ and do {
            last SWITCH if &codegen_compare($this, '<=', $pretty, $nesting, $context);
            push(@$pretty, "${indent}Int256_cmp(");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented}, ");
            &codegen_boxed($$this[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent}) <= 0");
            last SWITCH;
          };
        $$this[0] =~ /^TRUE$/ and do {
            push(@$pretty, "${indent}true");
            last SWITCH;
          };
        $$this[0] =~ /^FALSE$/ and do {
            push(@$pretty, "${indent}false");
            last SWITCH;
          };
        $$this[0] =~ /^UNDEF$/ and do {
            my $int256_undef = "int256_undef";
            $$CodeGen_Operands{UNDEF}{$int256_undef}++;
            last SWITCH;
          };
        $$this[0] =~ /^CONST$/ and do {
            my $cst0;
            my $type = &ctype($this);
            if ($$type{W} != $BOX) {
                my $value = Math::BigInt->new("$$this[1]")
                              ->bmod(Math::BigInt->new(2)->bpow($$type{W}));
                push(@$pretty, "${indent}(uint$$type{W}_t)UINT64_C($value)");
                last SWITCH;
            }
            if($$this[1] =~ /^[\-0-9]+$/) {
                use bigint;
                my $value = sprintf("%#x%08xULL", ($$this[1] >> 32) & 0xffffffff, $$this[1] & 0xffffffff);
                if($$this[1] >> 32 == 0) {
                    $value = sprintf("%#xULL", $$this[1] & 0xffffffff);
                }
                # A negative constant is a 64-bit two's-complement pattern; fromUInt64 would
                # zero-extend it into a huge positive across the container, so sign-extend
                # it with fromInt64 instead.
                if($$this[1] < 0) {
                    push(@$pretty, "${indent}Int256_fromInt64((int64_t)$value)");
                } else {
                    push(@$pretty, "${indent}Int256_fromUInt64($value)");
                }
            } else {
                # SYMBOLIC CONSTANT
                $cst0 = $$this[1];
                $$CodeGen_Operands{ENUM}{IDENT}{$cst0}++;
                push(@$pretty, "${indent}$cst0");
            }
            last SWITCH;
          };
        $$this[0] =~ /^METHOD$/ and do {
            my $proxy = $$this[1];
            $proxy =~ /%([0-9]+)(:(\d+))?/ or die "Expecting proxy instead of $$this[1]";
# Only generate access to RegClass encoded index. Immediate still be accessed through operands.
            my $type = &ctype($this);
            if($$CodeGen_Proxies{$proxy}{METHOD} eq "RegClass") {
                my $where = $$CodeGen_Proxies{$proxy}{WHERE};
                # An index into a register file: it is already a C integer, and boxing
                # it only to take it out again is the commonest waste in the whole tuple.
                if ($$type{W} != $BOX) {
                    push(@$pretty, "${indent}(uint$$type{W}_t)($where)");
                } else {
                    push(@$pretty, "${indent}Int256_fromInt64($where)");
                }
            } else {
                my $index = $$CodeGen_Proxies{$proxy}{INDEX};
                # An Immediate or a Modifier, which the shim hands back as an Int256_.
                # Signed immediates come back sign-extended, so the low bits are the
                # two's complement of the value and ctype's S says how to read them.
                if ($$type{W} != $BOX) {
                    push(@$pretty, "${indent}(uint$$type{W}_t)Int256_toUInt64("
                                 . "HELPER(operandRead)(this, $index))");
                } else {
                    push(@$pretty, "${indent}HELPER(operandRead)(this, $index)");
                }
            }
            last SWITCH;
          };
        $$this[0] =~ /^TEST$/ and do {
            &signature($this, $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^APPLY$/ and do {
            # APPLY Width Ident Arguments
            &signature($this, $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^EFFECT$/ and do {
            # EFFECT Stage Ident Arguments
            &signature($this, $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^THROW$/ and do {
            # THROW Ident
            &signature($this, $pretty, $nesting, $context);
            last SWITCH;
          };
        $$this[0] =~ /^BIND$/ and do {
            # BIND Variables APPLYT -- the destructuring of a tuple-valued call.
            #
            # The struct is taken into a temporary declared right here rather than at the
            # top of the function with the other variables: those are emitted as
            # `T name = 0;`, which a struct is not, and the temporary is single-use
            # anyway.  C99 lets it be declared where it is assigned, and every block this
            # can appear in is braced.
            my ($names, $tuple) = @{$this}[1, 2];
            my $widths = $$tuple[1];
            my $type = &_ctype_tuple($widths);
            my $temp = "_bind" . $CodeGen_Binds++;
            push(@$pretty, "${indent}$type $temp = ");
            &signature($tuple, $pretty, $nesting + 1, $context);
            # A command emits one statement and lets whatever contains it supply the
            # terminator -- SEQ pushes one per child, CodeGen one at the end.  This emits
            # several, so it terminates its own and leaves the last to the container,
            # exactly as a WRITE leaves its only one.
            push(@$pretty, ";");
            for (my $i = 0; $i < @{$names}; $i++) {
                my $name = $names->[$i];
                my $want = $Unbox && defined $CodeGen_VarTypes{$name}
                           ? $CodeGen_VarTypes{$name} : &_ctype_box();
                $$CodeGen_Operands{INT256}{$name} = &cdecl($want);
                # The element is exactly its declared width, so the conversion is a
                # no-op whenever the bind typed the variable -- which is every time,
                # unless a WRITE elsewhere disagreed and pushed it to the container.
                my ($prefix, $suffix) = &cconv(&_ctype_element($widths->[$i]), $want);
                push(@$pretty, "${indent}$name = $prefix$temp._$i$suffix");
                push(@$pretty, ";") unless $i == $#{$names};
            }
            last SWITCH;
          };
        $$this[0] =~ /^WRITE$/ and do {
            # WRITE Section Variable Integer
            my $Section = $$this[1];
            my $Variable = $$this[2];
            my $Integer = $$this[3];
            my $type = $Unbox && defined $CodeGen_VarTypes{$Variable}
                       ? $CodeGen_VarTypes{$Variable} : &_ctype_box();
            # The declaration BE/LAO/BIN/Behavior.pl emits for this variable.
            $$CodeGen_Operands{INT256}{$Variable} = &cdecl($type);
            if ($Section) {
                my ($prefix, $suffix) = &codegen_write($Section, $context);
                push(@$pretty, "${indent}${Variable}$prefix = (");
                &codegen_boxed($Integer, $pretty, $nesting + 1, $context);
                push(@$pretty, ")${indent}$suffix");
            } else {
                push(@$pretty, "${indent}$Variable = ");
                &codegen_operand($Integer, $type, $pretty, $nesting + 1, $context);
            }
            last SWITCH;
          };
        $$this[0] =~ /^COMMIT$/ and do {
            # COMMIT Stage Proxy Integer
            confess "$$this[0]: Not yet implemented";
            last SWITCH;
          };
        $$this[0] =~ /^READ$/ and do {
            # READ Section Variable
            my $Section = $$this[1];
            my $Variable = $$this[2];
            if ($Section) {
                my ($prefix, $suffix) = &codegen_read($Section, $context);
                push(@$pretty, "${indent}$prefix$Variable$suffix");
            } else {
                push(@$pretty, "${indent}$Variable");
            }
            last SWITCH;
          };
        $$this[0] =~ /^ACCESS$/ and do {
            # ACCESS Stage Proxy
            confess "$$this[0]: Not yet implemented";
            last SWITCH;
          };
        $$this[0] =~ /^STORE$/ and do {
            # STORE Stage Location BitField Mask
            my $Stage    = $$this[1];
            my $Location = $$this[2];
            my $BitField = $$this[3];
            my $Mask = $$this[4];
            if (defined $Storage{$$Location[1]}->{KIND}
                and $Storage{$$Location[1]}->{KIND} eq "Memory") {
                confess "Masked STORE not supported" if defined $Mask;
                push(@$pretty, "${indent}HELPER(store_$$Location[1])(this${indent_incremented}, ");
                &codegen_boxed($$Location[3], $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}, ");
                &codegen_boxed($$Location[2], $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}, ");
                &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent})");
                $$CodeGen_Operands{ENUM}{MEMORY}{$$Location[1]}++;
            } else {
                my $address = $$Location[2][1];
                my $extent = $$Location[3][1];
                my $width = $Storage{$$Location[1]}->{WIDTH};
                if ($$Location[2][0] ne "CONST") {
                    confess "Extent is not 1 and address not constant" unless $extent == 1;
                    if ($$Location[2][0] eq "METHOD") {
                        my $proxy = $$Location[2][1];
                        $proxy =~ /%([0-9]+)(:(\d+))?/ or die "Expecting proxy instead of $$Location[2][1]";
                        my ($rank, $multi, $bias) = ($1, $2, $3);
                        my $index = $$CodeGen_Proxies{$proxy}{INDEX};
                        $$CodeGen_Operands{WRITE}{$proxy}{REGFILE} = $$Location[1];
                        $$CodeGen_Operands{WRITE}{$proxy}{STAGE} = $Stage;
                        if (defined $Mask) {
                            confess "STORE mask not constant" if $Mask->[0] ne 'CONST';
                            my ($static_name, $static_value) = &codegen_mask("static", $Mask->[1]);
                            unless (defined $$CodeGen_Statics{$static_name}) {
                                $$CodeGen_Statics{$static_name} = $static_value;
                            }
                            (my $mask_name = "mask" . $proxy) =~ s/\W/_/g;
  #$$CodeGen_Operands{MASK}{$mask_name} = 1;
  #push(@$pretty, "${indent}$mask_name = Int256_or($mask_name, $static_name);");
                            push(@$pretty, "${indent}HELPER(operandFromValue)(this, $rank, $index, &$static_name, ");
                            &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                            push(@$pretty, "${indent})");
                        } else {
                            push(@$pretty, "${indent}HELPER(operandFromValue)(this, $rank, $index, 0, ");
                            &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                            push(@$pretty, "${indent})");
                        }
                    } else {
                        confess "Masked STORE not supported" if defined $Mask;
                        push(@$pretty, "${indent}HELPER(writeToStorage_$$Location[1])(this, $Stage, ");
                        # Enable commit stage for this write to storage
                        $$CodeGen_Operands{COMMITS}{$$Location[1]} = 1;
                        push(@$pretty, "${indent_incremented}Int256_toUInt32(");
                        &codegen_boxed($$Location[2], $pretty, $nesting + 1, $context);
                        push(@$pretty, "${indent}), 1, $width, ");
                        &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                        push(@$pretty, "${indent})");
                    }
                } else {
                    confess "Masked STORE not supported" if defined $Mask;
                    if ($extent == 1) {
                        push(@$pretty, "${indent}HELPER(writeToStorage_$$Location[1])(this, $Stage, $address, 1, $width, ");
                        # Enable commit stage for this write to storage
                        $$CodeGen_Operands{COMMITS}{$$Location[1]} = 1;
                        &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                        push(@$pretty, "${indent})");
                        if($$Location[2][1] !~ /^[0-9\-]+$/) {
                            $$CodeGen_Operands{ENUM}{IDENT}{$$Location[2][1]}++;
                        }
                    } else {
                        if(not defined $Storage{$$Location[1]}->{WIDTH}) {
                            confess "$$Location[1]: Storage width unknown";
                        }
                        if($$Location[2][1] !~ /^[0-9\-]+$/) {
                            $$CodeGen_Operands{ENUM}{IDENT}{$$Location[2][1]}++;
                        }
                        confess "Storage wider than 256 bits" if $extent * $width > 256;
                        push(@$pretty, "${indent}HELPER(writeToStorage_$$Location[1])(this, $Stage, $address, $extent, $width, ");
                        # Enable commit stage for this write to storage
                        $$CodeGen_Operands{COMMITS}{$$Location[1]} = 1;
                        &codegen_boxed($BitField, $pretty, $nesting + 1, $context);
                        push(@$pretty, "${indent})");
                    }
                }
                $$CodeGen_Operands{ENUM}{REGISTER}{$$Location[1]}++;
            }
            last SWITCH;
          };
        $$this[0] =~ /^LOAD$/ and do {
            # LOAD Stage Location
            my $Stage    = $$this[1];
            my $Location = $$this[2];
            if (defined $Storage{$$Location[1]}->{KIND}
                and $Storage{$$Location[1]}->{KIND} eq "Memory") {
                push(@$pretty, "${indent}HELPER(load_$$Location[1])(this${indent_incremented}, ");
                &codegen_boxed($$Location[3], $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent_incremented}, ");
                &codegen_boxed($$Location[2], $pretty, $nesting + 1, $context);
                push(@$pretty, "${indent})");
                $$CodeGen_Operands{ENUM}{MEMORY}{$$Location[1]}++;
            } else {
                confess "LOAD extent is not constant for ".$CodeGen_Opcode->name() if($$Location[3][0] ne "CONST");
                my $address = $$Location[2][1];
                my $extent = $$Location[3][1];
                my $width = $Storage{$$Location[1]}->{WIDTH};
                if ($$Location[2][0] ne "CONST") {
                    confess "Extent is not 1 and address not constant" unless $extent == 1;
                    if ($$Location[2][0] eq "METHOD") {
                        my $proxy = $$Location[2][1];
                        $proxy =~ /%([0-9]+)(:(\d+))?/ or die "Expecting proxy instead of $$Location[2][1]";
                        $$CodeGen_Operands{READ}{$proxy}{REGFILE} = $$Location[1];
                        $$CodeGen_Operands{READ}{$proxy}{STAGE} = $Stage;
                        my $index = $$CodeGen_Proxies{$proxy}{INDEX};
                        push(@$pretty, "${indent}HELPER(operandRead)(this, $index)");
                    } else {
                        push(@$pretty, "${indent}HELPER(readFromStorage_$$Location[1])(this, $Stage, ");
                        push(@$pretty, "${indent_incremented}Int256_toUInt32(");
                        &codegen_boxed($$Location[2], $pretty, $nesting + 1, $context);
                        push(@$pretty, "${indent}), 1, $width)");
                    }
                } else {
                    if ($extent == 1) {
                        push(@$pretty, "${indent}HELPER(readFromStorage_$$Location[1])(this, $Stage, $address, 1, $width)");
                        if($$Location[2][1] !~ /^[0-9\-]+$/) {
                            $$CodeGen_Operands{ENUM}{IDENT}{$address}++;
                        }
                    } else {
                        if(not defined $Storage{$$Location[1]}->{WIDTH}) {
                            confess "$$Location[1]: Storage width unknown";
                        }
                        if($$Location[2][1] !~ /^[0-9\-]+$/) {
                            $$CodeGen_Operands{ENUM}{IDENT}{$$Location[2][1]}++;
                        }
                        confess "Storage wider than 256 bits" if $extent * $width > 256;
                        push(@$pretty,
"${indent_incremented}HELPER(readFromStorage_$$Location[1])(this, $Stage, $address, $extent, $width)");
                    }
                }
                $$CodeGen_Operands{ENUM}{REGISTER}{$$Location[1]}++;
            }
            last SWITCH;
          };
        $$this[0] =~ /^PROBE$/ and do {
            # PROBE Stage Location
            my $Location = $$this[2];
            # Check if the change is correct.
            # if (!(defined $Storage{$$Location[1]}->{KIND} and 
            #         $Storage{$$Location[1]}->{KIND} eq "Memory")) {
            #    confess "$$Location[1]: Not a memory storage"
            # }
            if (!(defined $Storage{$$Location[1]}->{KIND} and
                    $Storage{$$Location[1]}->{KIND} eq "Memory")) {
                $$CodeGen_Operands{ENUM}{MEMORY}{$$Location[1]}++;
            }
            else {
                $$CodeGen_Operands{ENUM}{REGISTER}{$$Location[1]}++;
            }
            push(@$pretty, "${indent}HELPER(probe_$$Location[1])(this, ");
            &codegen_boxed($$Location[3], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent_incremented},");
            &codegen_boxed($$Location[2], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            last SWITCH;
          };
        $$this[0] =~ /^SKIP$/ and do {
            # SKIP Arguments
            last SWITCH;
          };
        $$this[0] =~ /^CANCEL$/ and do {
            # CANCEL
            push(@$pretty, "${indent}HELPER(cancel)(this);");
            last SWITCH;
          };
        $$this[0] =~ /^SEQ$/ and do {
            # SEQ Commands
            for (my $i = 1; $i < @$this; $i++) {
                &codegen_boxed($$this[$i], $pretty, $nesting, $context);
                push(@$pretty, ";");
            }
            last SWITCH;
          };
        $$this[0] =~ /^IF$/ and do {
            # IF Boolean Command Command
            push(@$pretty, "${indent}if (");
            &codegen_boxed($$this[1], $pretty, $nesting + 1, $context);
            push(@$pretty, "${indent})");
            push(@$pretty, "${indent}{");
            &codegen_boxed($$this[2], $pretty, $nesting+1, $context);
            push(@$pretty, "${indent_incremented};");
            my @else = $$this[3][0];
            if ($else[0] ne 'SKIP') {
                push(@$pretty, "${indent}}");
                push(@$pretty, "${indent}else {");
                &codegen_boxed($$this[3], $pretty, $nesting+1, $context);
                push(@$pretty, "${indent_incremented};");
            }
            push(@$pretty, "${indent}}");
            last SWITCH;
          };
        $$this[0] =~ /^AGGL$/ and do {
            # AGGL Storage Address Extent
            confess "Should not be here";
            last SWITCH;
          };
        $$this[0] =~ /^AGGB$/ and do {
            # AGGB Storage Address Extent
            confess "Should not be here";
            last SWITCH;
          };
        $$this[0] =~ /^FOR$/ and do {
            my @for_node = @{$this};
            my $var = $for_node[1];
            my (undef, $begin, $end, $step) = @{$for_node[2]};
            my %cont = %{$context};
            my @cmds = splice @for_node, 3;
            while (($step > 0 && $begin < $end) || ($step < 0 && $begin > $end)) {
                if (exists $cont{$var}) {
                    die "variable $var already defined."
                }
                $cont{$var} = $begin;
                foreach my $cmd (@cmds) {
                    &codegen_boxed($cmd, $pretty, $nesting+1, \%cont);
                    push @$pretty, ";";
                }
                delete $cont{$var};
                $begin += $step;
            }
            last SWITCH;
          };
        $$this[0] =~ /^INDEX$/ and do {
            my $var = $$this[1];
            my %cont = %{$context};
            if (exists $cont{$var}) {
                push @$pretty, $cont{$var};
            } else {
                die "variable $var is unbound.";
            }
            last SWITCH;
          };
        confess "Unrecognized $$this[0]\n";
    }
}

=head1 NAME

Behavior -- Behavior language parser

=head1 SYNOPSIS

  use Behavior;

  &Behavior::yyin(@input);
  &Behavior::yyparse && die "syntax error at ", &Behavior::yylval;
  &Behavior::yyflush;

=head1 DESCRIPTION

=head1 FUNCTIONS

=over 4

=item B<yyin>($input);

Fills the input buffer for $input parsing.

=item B<yyparse>();

Parse the input buffer, returning non-zero on failure.

=item B<yylval>($size);

Sets the number of tokens memorized before the current
token. Useful to display error messages.

=item B<yyflush>();

Flush the input buffer. Useful after an error has been
detected, so as to start with a new, clean buffer.

=item B<yytree>();

Returns the parse tree. Use Data::Dumper to figure what it is.

=back

=head1 LIMITATIONS

=head1 AUTHOR

Benoit Dupont de Dinechin

=cut

#
# Initialize the Behavior tables. 
#
our %pipeline;
sub yyinit {
    foreach my $processor (@Processor::table) {
        my @pipeline = split ' ', $processor->attribute("pipeline");
        my @stages = split ' ', $processor->attribute("stages");
        croak "pipeline names and stages lists mismatch" unless @pipeline == @stages;
        while (@pipeline) {
            my $name = shift @pipeline;
            my $stage = shift @stages;
            my $contents = $pipeline{$name};
            #print STDERR "pipeline($name) = $stage\n";
            unless ($yycheck) {
                croak "pipeline stage $name already defined as $contents" if defined $contents;
            }
            $pipeline{$name} = $stage;
        }
    }
    foreach my $storage (@Storage::table) {
        my $name = $storage->name();
        my $kind = $storage->attribute("kind");
        my $width = $storage->attribute("width");
        if ($kind eq 'Constant') {
            my $contents = $storage->contents();
            #print STDERR "Storage Constant($name) = $contents\n";
            my $constant = &Constant($name);
            croak "Storage Constant $name already defined" if defined $constant;
            &Constant($name, $contents);
        } else {
            &Storage($name, { KIND=>$kind, WIDTH=>$width });
        }
    }
    foreach my $regFile (&MDS::regFiles()) {
        my $name = $regFile->regFileName();
        my $width = $regFile->attribute("width");
        &Storage($name, { WIDTH=>$width });
        my @registers = $regFile->access("registers");
        my $index = 0;
        foreach my $register (@registers) {
            my $name = $register->name();
            my $constant = &Constant($name);
            croak "Register Constant $name already defined" if defined $constant;
            #print STDERR "Register Constant($name) = $index\n";
            &Constant($name, $index);
            $index++;
        }
    }
    foreach my $regField (@RegField::table) {
        my $name = $regField->name();
        my $constant = &Constant($name);
        my $offset = $regField->attribute("offset");
        if (defined $constant and $constant != $offset and $name ne "PCR_CAR") {
            croak "RegField Constant $name already defined";
        }
        #print STDERR "RegField Constant($name) = $offset\n";
        &Constant($name, $offset);
    }
}

#
# Scanner code: export &yylval, &yyin, &yylex.
#

our $yylval = undef;
our @yylval = ();
our $yykeep = 8;
our $yylkeep;
sub yylval {
    $yylkeep = shift;
    if (defined $yylkeep) {
        shift @yylval while @yylval > $yylkeep;
    }
    map { "'$_' " } @yylval;
}

our @yyin = ();
sub yyin {
    while (@_) {
        my $buffer = shift;
        push @yyin, grep {length($_)} split ' ', $buffer;
    }
}

sub yyflush {
    @yyin = ();
    @yylval = ();
}

my $yytree;
sub yytree {
    return $yytree;
}

our $yylast = '';
sub yylex {
    my $token;
    return '' unless (@yyin);
    my $value = shift @yyin;
#%token INTNUM SYMNUM IDENT PROXY
#%token SEQ IF EFFECT STORE COMMIT WRITE BIND THROW MACRO SKIP LOAD ACCESS READ PROBE AGGL AGGB SLICE
#%token UNDEF PROPERTY CONST METHOD APPLY F2I SX ZX SAT SATU CLZ CLS CTZ CBS SWAP ROR ROL
#%token SELECT ADD SUB MUL DIV REM MOD SHR SHL AND IOR XOR MIN MAX NOT NEG ABS B2I
#%token TRUE FALSE TEST NE EQ GT LE GE LT ANDL IORL XORL NOTL I2B I2F
#%token FOR INDEX RANGE
    if ($value =~ s/^(0x[0-9a-fA-F]+)//) {
        ($token, $yylval) = ('INTNUM', $1);
        # $yylval = oct($yylval) if $yylval =~ /^0/;
    } elsif ($value =~ s/^(0b[01]+)//) {
        ($token, $yylval) = ('INTNUM', $1);
        # $yylval = oct($yylval) if $yylval =~ /^0/;
    } elsif ($value =~ s/^(\-?\d+)//) {
        ($token, $yylval) = ('INTNUM', $1);
    } elsif ($value =~ s/^(\%\d+(:\d+)?)//) {
        ($token, $yylval) = ('PROXY', $1);
    } elsif ($value =~ s/^([a-zA-Z_]\w*)//) {
        if ($yylast eq '(') {
            ($token, $yylval) = ($1, $1);
        } else {
            ($token, $yylval) = ('IDENT', $1);
            if ($yylast eq 'CONST') {
                $token = 'SYMNUM';
                my $constant = &Constant($yylval);
                if (defined $constant) {
                    if (!ref $constant) {
                        ($token, $yylval) = ('INTNUM', $constant);
                    }
                } elsif (!$yycheck) {
                    &Error("Unknown symbolic constant $yylval");
                }
            }
        }
    } elsif ($value =~ s/^((\(\*)|(\*\))|(\W))//) {
        ($token, $yylval) = ($1, $1);
    } else {
        croak "unrecognized token '$value'";
    }
    unshift @yyin, $value if length($value);
    if (defined $yylkeep) {
        push @yylval, $yylval;
        shift @yylval if @yylval > $yylkeep;
    }
    $yylast = $token unless $token eq '.';
    return $token;
}

1;

